  color: rgba(255, 255, 255, 0.85);
  margin-bottom: 32px;
  font-weight: 400;
  font-style: italic;
  text-shadow: 0 2px 12px rgba(0, 0, 0, 0.5);
  max-width: 600px;
}

.view-map-btn {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  background: linear-gradient(135deg, #d4a574 0%, #c49563 100%);
  color: #ffffff;
  padding: 16px 32px;
  border-radius: 12px;
  font-size: 16px;
  font-weight: 700;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  border: 1px solid rgba(255, 255, 255, 0.2);
  box-shadow: 0 4px 20px rgba(212, 165, 116, 0.4),
              0 0 30px rgba(212, 165, 116, 0.2),
              inset 0 1px 0 rgba(255, 255, 255, 0.2);
}

.view-map-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 28px rgba(212, 165, 116, 0.5),
              0 0 40px rgba(212, 165, 116, 0.3),
              inset 0 1px 0 rgba(255, 255, 255, 0.3);
}

.map-icon {
  font-size: 20px;
  filter: drop-shadow(0 2px 4px rgba(0, 0, 0, 0.3));
}

.detail-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 48px;
  position: relative;
  z-index: 3;
  margin-top: -60px;
}

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 24px;
  margin-bottom: 80px;
}

.stat-glass-card {
  background: linear-gradient(145deg, rgba(36, 36, 36, 0.5), rgba(26, 26, 26, 0.3));
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  padding: 32px 24px;
  border-radius: 20px;
  text-align: center;
  border: 1px solid rgba(255, 255, 255, 0.08);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4),
              inset 0 1px 0 rgba(255, 255, 255, 0.08);
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.stat-glass-card:hover {
  transform: translateY(-4px);
  border-color: rgba(212, 165, 116, 0.2);
  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.5),
              0 0 30px rgba(212, 165, 116, 0.1),
              inset 0 1px 0 rgba(255, 255, 255, 0.12);
}

.stat-icon {
  font-size: 48px;
  margin-bottom: 16px;
  filter: drop-shadow(0 4px 12px rgba(212, 165, 116, 0.3));
  transition: transform 0.3s ease;
}

.stat-glass-card:hover .stat-icon {
  transform: scale(1.1);
}

.stat-value {
  font-size: 40px;
  font-weight: 800;
  color: #d4a574;
  margin-bottom: 8px;
  text-shadow: 0 2px 12px rgba(212, 165, 116, 0.4);
  letter-spacing: -1px;
}

.stat-label {
  font-size: 14px;
  color: rgba(255, 255, 255, 0.6);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 1px;
}

.difficulty-badge-detail {
  display: inline-block;
  padding: 8px 20px;
  border-radius: 20px;
  font-size: 14px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: #ffffff;
  border: 1px solid rgba(255, 255, 255, 0.2);
}

.start-hike-section {
  margin-bottom: 60px;
  display: flex;
  justify-content: center;
  animation: fadeInUp 0.5s ease-out;
}

.btn-start-hike {
  position: relative;
  padding: 1.25rem 2rem;
  background: linear-gradient(135deg, #d4a574 0%, #a67c52 100%);
  border: none;
  border-radius: 16px;
  cursor: pointer;
  transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
  box-shadow: 0 8px 32px rgba(212, 165, 116, 0.4),
              0 0 60px rgba(212, 165, 116, 0.2),
              inset 0 1px 0 rgba(255, 255, 255, 0.3);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.5rem;
  overflow: hidden;
}

.btn-start-hike::before {
  content: '';
  position: absolute;
  top: 0;
  left: -100%;
  width: 100%;
  height: 100%;
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.3), transparent);
  transition: left 0.5s;
}

.btn-start-hike:hover::before {
  left: 100%;
}

.btn-start-hike:hover {
  transform: translateY(-4px) scale(1.02);
  box-shadow: 0 12px 48px rgba(212, 165, 116, 0.5),
              0 0 80px rgba(212, 165, 116, 0.3),
              inset 0 1px 0 rgba(255, 255, 255, 0.4);
}

.btn-start-hike:active {
  transform: translateY(-2px) scale(0.98);
}

.btn-icon {
  font-size: 2rem;
  filter: drop-shadow(0 2px 8px rgba(0, 0, 0, 0.3));
}

.btn-text {
  font-size: 1.25rem;
  font-weight: 700;
  color: #0a0a0a;
  letter-spacing: 0.5px;
  text-shadow: 0 1px 2px rgba(255, 255, 255, 0.3);
}

.btn-subtext {
  font-size: 0.8rem;
  color: rgba(10, 10, 10, 0.7);
  font-weight: 500;
}

.trail-overview-section {
  margin-bottom: 80px;
  animation: fadeInUp 0.6s ease-out;
}

.map-section {
  margin-bottom: 80px;
  animation: fadeInUp 0.8s ease-out;
}

@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.section-header {
  margin-bottom: 32px;
}

.section-title {
  font-size: 36px;
  font-weight: 800;
  color: #ffffff;
  margin-bottom: 16px;
  letter-spacing: -0.5px;
  text-shadow: 0 2px 12px rgba(0, 0, 0, 0.4);
}

.gradient-divider {
  height: 4px;
  background: linear-gradient(90deg, 
    #d4a574 0%, 
    rgba(212, 165, 116, 0.5) 50%, 
    transparent 100%);
  border-radius: 2px;
  box-shadow: 0 2px 8px rgba(212, 165, 116, 0.3);
}

.overview-text {
  font-size: 18px;
  line-height: 1.9;
  color: rgba(255, 255, 255, 0.8);
  max-width: 900px;
  margin: 0 auto;
  text-align: left;
  font-weight: 400;
}

.poi-section {
  margin-bottom: 80px;
}

.poi-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(400px, 1fr));
  gap: 24px;
}

.poi-card-premium {
  background: linear-gradient(145deg, rgba(24, 51, 44, 0.3), rgba(18, 38, 33, 0.2));
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  padding: 28px;
  border-radius: 16px;
  display: flex;
  gap: 20px;
  align-items: flex-start;
  border: 1px solid rgba(255, 255, 255, 0.06);
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);
}

.poi-card-premium:hover {
  background: linear-gradient(145deg, rgba(24, 51, 44, 0.5), rgba(18, 38, 33, 0.3));
  border-color: rgba(212, 165, 116, 0.2);
  transform: translateY(-4px);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4),
              0 0 24px rgba(212, 165, 116, 0.1);
}

.poi-icon-circle {
  width: 56px;
  height: 56px;
  background: linear-gradient(135deg, rgba(212, 165, 116, 0.2), rgba(212, 165, 116, 0.1));
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 28px;
  flex-shrink: 0;
  border: 1px solid rgba(212, 165, 116, 0.3);
  box-shadow: 0 4px 16px rgba(212, 165, 116, 0.2),
              inset 0 1px 0 rgba(255, 255, 255, 0.1);
}

.poi-content {
  flex: 1;
}

.poi-name {
  font-size: 18px;
  font-weight: 700;
  color: #ffffff;
  margin-bottom: 8px;
  letter-spacing: -0.2px;
}

.poi-description {
  font-size: 15px;
  color: rgba(255, 255, 255, 0.7);
  line-height: 1.6;
}

.footer-meta {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 24px;
  padding-top: 40px;
  border-top: 1px solid rgba(255, 255, 255, 0.08);
}

.meta-card {
  background: linear-gradient(145deg, rgba(36, 36, 36, 0.4), rgba(26, 26, 26, 0.2));
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  padding: 24px;
  border-radius: 16px;
  display: flex;
  align-items: center;
  gap: 16px;
  border: 1px solid rgba(255, 255, 255, 0.05);
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.3);
  transition: all 0.3s ease;
}

.meta-card:hover {
  border-color: rgba(212, 165, 116, 0.2);
  box-shadow: 0 6px 24px rgba(0, 0, 0, 0.4);
}

.meta-icon {
  font-size: 32px;
  filter: drop-shadow(0 2px 8px rgba(212, 165, 116, 0.3));
}

.meta-content {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.meta-label {
  font-size: 13px;
  color: rgba(255, 255, 255, 0.5);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.meta-value {
  font-size: 16px;
  font-weight: 700;
  color: #ffffff;
  text-transform: capitalize;
}

@media (max-width: 968px) {
  .detail-hero {
    min-height: max(500px, 60svh);
    height: auto;
  }

  .detail-hero-content {
    padding: calc(var(--safe-top) + var(--header-h) + 20px) 32px 40px;
    z-index: 5;
  }

  .hero-title {
    font-size: 48px;
  }

  .hero-tagline {
    font-size: 18px;
  }

  .detail-container {
    padding: 0 32px;
  }

  .stats-grid {
    grid-template-columns: repeat(2, 1fr);
    gap: 16px;
  }

  .section-title {
    font-size: 28px;
  }

  .poi-grid {
    grid-template-columns: 1fr;
  }

  .footer-meta {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 640px) {
  .detail-hero {
    min-height: max(440px, 50svh);
  }

  .detail-hero-content {
    padding: calc(var(--safe-top) + var(--header-h) + 20px) 20px 30px;
  }

  .hero-title {
    font-size: 36px;
  }

  .hero-tagline {
    font-size: 16px;
  }

  .detail-container {
    padding: 0 20px;
    margin-top: -40px;
  }

  .stats-grid {
    gap: 12px;
  }

  .stat-glass-card {
    padding: 24px 16px;
  }

  .stat-value {
    font-size: 32px;
  }

  .section-title {
    font-size: 24px;
  }

  .overview-text {
    font-size: 16px;
  }

  .back-button,
  .action-btn,
  .review-submit,
  .start-hike-btn {
    min-height: 48px;
    min-width: 48px;
    padding: 14px 24px;
    font-size: 15px;
  }

  .action-buttons {
    flex-direction: column;
    gap: 12px;
  }

  .action-buttons button {
    width: 100%;
  }

  .review-form textarea {
    min-height: 120px;
    font-size: 16px;
  }

  .review-form input,
  .review-form select {
    min-height: 48px;
    font-size: 16px;
  }
}

/* Hero Fade-in Animation */
.hero-fade-in {
  animation: heroFadeIn 1s ease-out;
}

@keyframes heroFadeIn {
  from {
    opacity: 0;
    transform: translateY(30px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* Hero Top Row */
.hero-top-row {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 20px;
  flex-wrap: wrap;
}

/* Difficulty Badge in Hero */
.difficulty-badge-hero {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 10px 24px;
  border-radius: 24px;
  font-size: 15px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: #ffffff;
  border: 1px solid rgba(255, 255, 255, 0.3);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  transition: all 0.3s ease;
}

.difficulty-badge-hero:hover {
  transform: scale(1.05);
}

/* Stats Grid Animations */
.stats-animated {
  opacity: 0;
  transform: translateY(30px);
}

.stats-animated.animated-in {
  opacity: 1;
  transform: translateY(0);
  transition: all 0.6s cubic-bezier(0.4, 0, 0.2, 1);
}

.stats-animated.animated-in .stat-glass-card {
  animation: statPopIn 0.5s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
  opacity: 0;
}

@keyframes statPopIn {
  from {
    opacity: 0;
    transform: scale(0.8) translateY(30px);
  }
  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

/* Glowing Icon Effect */
.stat-icon-glow {
  animation: iconGlow 3s ease-in-out infinite;
}

@keyframes iconGlow {
  0%, 100% {
    filter: drop-shadow(0 4px 12px rgba(212, 165, 116, 0.3));
  }
  50% {
    filter: drop-shadow(0 4px 20px rgba(212, 165, 116, 0.6));
  }
}

/* Elevation Profile Section */
.elevation-profile-section {
  margin-bottom: 60px;
  opacity: 0;
  transform: translateY(30px);
}

.elevation-profile-section.animated-in {
  opacity: 1;
  transform: translateY(0);
  transition: all 0.8s cubic-bezier(0.4, 0, 0.2, 1);
}

.elevation-chart-container {
  background: linear-gradient(145deg, rgba(36, 36, 36, 0.4), rgba(26, 26, 26, 0.3));
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  padding: 32px;
  border-radius: 20px;
  border: 1px solid rgba(255, 255, 255, 0.08);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4);
}

.elevation-chart {
  width: 100%;
  height: auto;
  filter: drop-shadow(0 2px 8px rgba(212, 165, 116, 0.2));
}

.elevation-line {
  stroke-dasharray: 2000;
  stroke-dashoffset: 2000;
  animation: drawLine 2s ease-out forwards;
}

.elevation-area {
  opacity: 0;
  animation: fadeInArea 1.5s ease-out 0.5s forwards;
}

@keyframes drawLine {
  to {
    stroke-dashoffset: 0;
  }
}

@keyframes fadeInArea {
  to {
    opacity: 1;
  }
}

.elevation-axis {
  display: flex;
  justify-content: space-between;
  margin-top: 16px;
  padding: 0 10px;
}

.elevation-label {
  font-size: 14px;
  color: rgba(255, 255, 255, 0.6);
  font-weight: 600;
}

/* Pulse Animation for Start Hike Button */
.btn-pulse {
  animation: buttonPulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite;
}

@keyframes buttonPulse {
  0%, 100% {
    transform: scale(1);
    box-shadow: 0 8px 32px rgba(212, 165, 116, 0.4),
                0 0 60px rgba(212, 165, 116, 0.2),
                inset 0 1px 0 rgba(255, 255, 255, 0.3);
  }
  50% {
    transform: scale(1.02);
    box-shadow: 0 12px 40px rgba(212, 165, 116, 0.5),
                0 0 80px rgba(212, 165, 116, 0.3),
                inset 0 1px 0 rgba(255, 255, 255, 0.4);
  }
}

.btn-pulse:hover {
  animation: none;
  transform: translateY(-4px) scale(1.05);
}

/* Reduced Motion Support */
@media (prefers-reduced-motion: reduce) {
  .detail-hero-image {
    transform: none !important;
    transition: none !important;
  }

  .hero-fade-in {
    animation: none;
  }

  .stats-animated,
  .elevation-profile-section {
    opacity: 1 !important;
    transform: none !important;
  }

  .stat-glass-card {
    animation: none !important;
  }

  .elevation-line,
  .elevation-area {
    animation: none !important;
    stroke-dashoffset: 0 !important;
    opacity: 1 !important;
  }

  .btn-pulse {
    animation: none !important;
  }

  .stat-icon-glow {
    animation: none !important;
  }

  .save-trail-btn.saved .save-icon {
    animation: none !important;
  }
}

/* Mobile Responsive Design */
@media screen and (max-width: 768px) {
  .detail-hero {
    min-height: max(440px, 55svh);
  }

  .detail-hero-image {
    background-size: cover;
    background-position: center;
  }

  .save-trail-btn {
    top: 80px;
    right: 20px;
    width: 50px;
    height: 50px;
  }

  .save-icon {
    font-size: 24px;
  }

  .hero-title {
    font-size: 40px;
  }

  .hero-tagline {
    font-size: 16px;
  }

  .detail-hero-content {
    padding: 40px 24px;
  }

  .stats-grid {
    grid-template-columns: repeat(2, 1fr);
    gap: 16px;
  }

  .stat-value {
    font-size: 32px;
  }

  .stat-icon {
    font-size: 36px;
  }

  .elevation-chart-container {
    padding: 20px;
  }

  .hero-top-row {
    gap: 12px;
  }

  .difficulty-badge-hero {
    font-size: 13px;
    padding: 8px 16px;
  }

  .btn-start-hike {
    padding: 1.5rem 2rem;
  }
}

@media screen and (max-width: 480px) {
  .detail-container {
    padding: 0 20px;
  }

  .hero-title {
    font-size: 32px;
  }

  .stats-grid {
    grid-template-columns: 1fr;
  }
}

