import React, { useState, useEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import axios from 'axios';
import FeaturedCarousel from './FeaturedCarousel';
import ThemeCards from './ThemeCards';
import './Home.css';

const API_URL = '/api';

function Home({ setCurrentView, viewTrail }) {
  const { t } = useTranslation();
  const [featuredTrails, setFeaturedTrails] = useState([]);
  const [loading, setLoading] = useState(true);
  const [scrollY, setScrollY] = useState(0);
  const heroRef = useRef(null);

  useEffect(() => {
    loadFeaturedTrails();

    // Parallax scroll effect
    const handleScroll = () => {
      setScrollY(window.scrollY);
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const loadFeaturedTrails = async () => {
    try {
      const response = await axios.get(`${API_URL}/trails`);

      if (response.data.trails && response.data.trails.length > 0) {
        // Select top 4 trails with highest ratings
        const topTrails = response.data.trails
          .sort((a, b) => (b.rating || 0) - (a.rating || 0))
          .slice(0, 4);
        setFeaturedTrails(topTrails);
      }
    } catch (error) {
      console.error('Error loading trails:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleThemeClick = (tags) => {
    // Navigate to catalog with filtered tags
    setCurrentView('catalog');
  };

  const handleScrollToContent = () => {
    const contentElement = document.querySelector('.home-content');
    if (contentElement) {
      contentElement.scrollIntoView({ behavior: 'smooth' });
    }
  };

  const logoOpacity = Math.max(0, 1 - (scrollY / 300));
  const preferReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

  return (
    <div className="home-page">
      {/* Enhanced Cinematic Parallax Hero Section */}
      <div className="hero-parallax-redesign" ref={heroRef}>
        <div 
          className="hero-layer hero-bg-redesign"
          style={!preferReducedMotion ? { transform: `translateY(${scrollY * 0.5}px)` } : {}}
        ></div>
        <div 
          className="hero-layer hero-mountains-back-redesign"
          style={!preferReducedMotion ? { transform: `translateY(${scrollY * 0.3}px)` } : {}}
        ></div>
        <div 
          className="hero-layer hero-mountains-front-redesign"
          style={!preferReducedMotion ? { transform: `translateY(${scrollY * 0.15}px)` } : {}}
        ></div>
        <div 
          className="hero-overlay-redesign"
          style={!preferReducedMotion ? { opacity: logoOpacity } : {}}
        ></div>

        <div className="hero-content-wrapper-redesign">
          <div className="container hero-content-redesign">
            <h1 
              className="hero-title-redesign" 
              style={!preferReducedMotion ? { transform: `translateY(${scrollY * 0.1}px)` } : {}}
            >
              {t('hero.title')}
            </h1>
            <p 
              className="hero-subtitle-redesign" 
              style={!preferReducedMotion ? { transform: `translateY(${scrollY * 0.12}px)` } : {}}
            >
              {t('hero.subtitle')}
            </p>
            <div 
              className="hero-cta-buttons-redesign" 
              style={!preferReducedMotion ? { transform: `translateY(${scrollY * 0.08}px)` } : {}}
            >
              <button className="hero-btn-primary-redesign" onClick={() => setCurrentView('recommendations')}>
                <span className="hero-btn-icon">✨</span>
                <span className="hero-btn-text">{t('home.smartRecommendations')}</span>
              </button>
              <button className="hero-btn-secondary-redesign" onClick={() => setCurrentView('catalog')}>
                <span className="hero-btn-icon">🗺️</span>
                <span className="hero-btn-text">{t('home.browseTrailCatalog')}</span>
              </button>
            </div>

            <div 
              className="hero-scroll-cue"
              onClick={handleScrollToContent}
              style={!preferReducedMotion ? { opacity: Math.max(0, 1 - (scrollY / 200)) } : {}}
            >
              <span className="scroll-cue-icon">🏔️</span>
              <span className="scroll-cue-text">{t('hero.scrollToExplore')}</span>
              <span className="scroll-cue-arrow">↓</span>
            </div>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="container home-content">
        {/* Featured Trails Carousel */}
        <section className="home-section">
          <div className="section-header-home">
            <h2 className="section-title-home">{t('home.featuredTrails')}</h2>
            <div className="gradient-divider-home"></div>
          </div>

          {loading ? (
            <div className="loading-carousel">{t('home.loadingRecommendation')}</div>
          ) : (
            <FeaturedCarousel trails={featuredTrails} onViewTrail={viewTrail} />
          )}
        </section>

        {/* Explore by Theme */}
        <section className="home-section">
          <ThemeCards onThemeClick={handleThemeClick} />
        </section>

        {/* Quick Actions */}
        <section className="home-section">
          <div className="quick-actions-grid">
            <div className="quick-action-card" onClick={() => setCurrentView('recommendations')}>
              <div className="quick-action-icon">✨</div>
              <h3 className="quick-action-title">{t('home.smartRecommendations')}</h3>
              <p className="quick-action-desc">{t('home.smartRecommendationsDesc')}</p>
              <span className="quick-action-arrow">→</span>
            </div>

            <div className="quick-action-card" onClick={() => setCurrentView('catalog')}>
              <div className="quick-action-icon">🗺️</div>
              <h3 className="quick-action-title">{t('home.browseTrailCatalog')}</h3>
              <p className="quick-action-desc">{t('home.browseTrailCatalogDesc')}</p>
              <span className="quick-action-arrow">→</span>
            </div>
          </div>
        </section>

        {/* Trust Badge */}
        <section className="home-section">
          <div className="trust-badge">
            <div className="trust-icon">✓</div>
            <p className="trust-text">{t('home.verifiedRoutes')}</p>
          </div>
        </section>
      </div>
    </div>
  );
}

export default Home;

web-frontend/src/components/Header.css.content:
.header {
  background: linear-gradient(145deg, rgba(26, 26, 26, 0.95), rgba(20, 20, 20, 0.9));
  backdrop-filter: blur(30px);
  -webkit-backdrop-filter: blur(30px);
  border-bottom: 1px solid rgba(255, 255, 255, 0.08);
  position: sticky;
  top: var(--safe-top);
  left: 0;
  right: 0;
  z-index: var(--z-navbar);
  overflow: visible;
  box-shadow: 0 4px 30px rgba(0, 0, 0, 0.4),
              inset 0 1px 0 rgba(255, 255, 255, 0.05);
}

.header::before {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 1px;
  background: linear-gradient(90deg, 
    transparent 0%, 
    rgba(212, 165, 116, 0.3) 50%, 
    transparent 100%);
}

.header-content {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 20px 32px;
  gap: 24px;
}

.logo {
  display: flex;
  align-items: center;
  gap: 14px;
  cursor: pointer;
  user-select: none;
  transition: transform 0.3s ease;
}

.logo:hover {
  transform: translateX(4px);
}

.logo-icon {
  font-size: 36px;
  filter: drop-shadow(0 4px 12px rgba(212, 165, 116, 0.4));
  transition: filter 0.3s ease;
}

.logo:hover .logo-icon {
  filter: drop-shadow(0 6px 20px rgba(212, 165, 116, 0.6));
}

.logo-text {
  font-size: 28px;
  font-weight: 800;
  background: linear-gradient(135deg, #ffffff 0%, rgba(255, 255, 255, 0.8) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  letter-spacing: -0.5px;
  text-shadow: 0 2px 8px rgba(0, 0, 0, 0.2);
}

.nav {
  display: flex;
  gap: 12px;
  background: linear-gradient(145deg, rgba(36, 36, 36, 0.5), rgba(26, 26, 26, 0.3));
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.05);
  border-radius: 16px;
  padding: 8px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3),
              inset 0 1px 0 rgba(255, 255, 255, 0.05);
}

.nav-link {
  background: transparent;
  color: var(--text-secondary);
  padding: 12px 24px;
  border-radius: 12px;
  font-size: 15px;
  font-weight: 600;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  border: 1px solid transparent;
  position: relative;
  overflow: hidden;
}

.nav-link::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(135deg, rgba(212, 165, 116, 0.1) 0%, transparent 100%);
  opacity: 0;
  transition: opacity 0.3s ease;
}

.nav-link:hover:not(.active) {
  background: linear-gradient(145deg, rgba(50, 50, 50, 0.6), rgba(40, 40, 40, 0.4));
  color: var(--text-primary);
  border-color: rgba(255, 255, 255, 0.08);
  transform: translateY(-1px);
}

.nav-link:hover:not(.active)::before {
  opacity: 1;
}

.nav-link.active {
  background: linear-gradient(135deg, var(--accent-primary) 0%, #c49563 100%);
  color: #fff;
  border-color: rgba(255, 255, 255, 0.2);
  box-shadow: 0 4px 16px rgba(212, 165, 116, 0.4),
              0 0 20px rgba(212, 165, 116, 0.2),
              inset 0 1px 0 rgba(255, 255, 255, 0.2);
  transform: translateY(-2px);
}

.header-actions {
  display: flex;
  align-items: center;
  gap: 16px;
}

.auth-buttons {
  display: flex;
  gap: 10px;
}

.auth-btn {
  padding: 10px 20px;
  border-radius: 12px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  border: none;
}

.login-btn {
  background: rgba(255, 255, 255, 0.08);
  color: white;
  border: 1px solid rgba(255, 255, 255, 0.15);
}

.login-btn:hover {
  background: rgba(255, 255, 255, 0.12);
  border-color: rgba(255, 255, 255, 0.25);
  transform: translateY(-2px);
}

.signup-btn {
  background: linear-gradient(135deg, #d4a574 0%, #c89960 100%);
  color: #0a0a0a;
  box-shadow: 0 4px 12px rgba(212, 165, 116, 0.3);
}

.signup-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 20px rgba(212, 165, 116, 0.5);
}

.user-name-header {
  max-width: 120px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* ========================================
   MOBILE REDESIGN STYLES (Phase 17H)
   ======================================== */

.header-mobile-redesign {
  background: linear-gradient(145deg, rgba(26, 26, 26, 0.98), rgba(20, 20, 20, 0.95));
  padding: 0;
}

.header-content-mobile {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 14px 20px;
  gap: 12px;
  max-width: 100%;
}

.logo-mobile {
  display: flex;
  align-items: center;
  gap: 10px;
  animation: fadeIn 0.6s ease;
}

@media (prefers-reduced-motion: reduce) {
  .logo-mobile {
    animation: none;
  }
}

@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(-10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.logo-icon-mobile {
  font-size: 26px;
  filter: drop-shadow(0 3px 10px rgba(212, 165, 116, 0.4));
}

.logo-text-mobile {
  font-size: 18px;
  font-weight: 800;
}

.header-actions-mobile {
  display: flex;
  align-items: center;
  gap: 10px;
}

.header-icon-btn {
  width: 44px;
  height: 44px;
  min-width: 44px;
  min-height: 44px;
  border-radius: 11px;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.08);
  color: var(--text-secondary);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  font-size: 18px;
  position: relative;
}

.header-icon-btn:hover {
  background: rgba(255, 255, 255, 0.1);
  border-color: rgba(212, 165, 116, 0.3);
  transform: scale(1.05);
  color: var(--text-primary);
}

.header-icon-btn:active {
  transform: scale(0.95);
}

.header-icon-btn:focus-visible {
  outline: 2px solid var(--accent-primary);
  outline-offset: 2px;
}

.language-btn-mobile {
  width: auto;
  padding: 0 10px;
  gap: 5px;
}

.language-icon {
  font-size: 17px;
  filter: drop-shadow(0 2px 4px rgba(0, 0, 0, 0.3));
}

.language-label-mobile {
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.02em;
}

.language-chevron {
  font-size: 9px;
  opacity: 0.6;
}

.user-avatar-mobile {
  width: 34px;
  height: 34px;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--accent-primary) 0%, #c49563 100%);
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 13px;
  font-weight: 700;
  box-shadow: 0 0 0 2px rgba(212, 165, 116, 0.3);
  transition: all 0.3s ease;
}

.user-btn-mobile:hover .user-avatar-mobile {
  box-shadow: 0 0 0 3px rgba(212, 165, 116, 0.5),
              0 0 20px rgba(212, 165, 116, 0.3);
}

.auth-icon {
  font-size: 18px;
  filter: drop-shadow(0 2px 4px rgba(0, 0, 0, 0.3));
}

.hamburger-icon {
  font-size: 20px;
  font-weight: 400;
  line-height: 1;
}

.hamburger-btn-mobile {
  background: linear-gradient(135deg, rgba(212, 165, 116, 0.15) 0%, rgba(212, 165, 116, 0.08) 100%);
  border-color: rgba(212, 165, 116, 0.2);
}

.hamburger-btn-mobile:hover {
  background: linear-gradient(135deg, rgba(212, 165, 116, 0.25) 0%, rgba(212, 165, 116, 0.15) 100%);
  border-color: rgba(212, 165, 116, 0.4);
}

@media (max-width: 768px) {
  .header {
    max-width: 100vw;
  }

  .header-content {
    flex-direction: row;
    gap: 8px;
    padding: 12px 16px;
    flex-wrap: wrap;
  }

  .logo {
    flex: 0 0 auto;
  }

  .logo-icon {
    font-size: 28px;
  }

  .logo-text {
    font-size: 20px;
  }

  .nav {
    order: 3;
    width: 100%;
    justify-content: center;
    flex-wrap: wrap;
    gap: 6px;
    padding: 6px;
  }

  .nav-link {
    font-size: 13px;
    padding: 8px 14px;
  }

  .user-name-header {
    display: none;
  }

  .auth-buttons {
    flex: 1;
    justify-content: flex-end;
    gap: 6px;
  }

  .auth-btn {
    font-size: 13px;
    padding: 8px 14px;
  }
}

@media (max-width: 480px) {
  .header-content-mobile {
    padding: 10px 12px;
    gap: 6px;
  }

  .logo-icon-mobile {
    font-size: 24px;
  }

  .logo-text-mobile {
    font-size: 17px;
  }

  .header-actions-mobile {
    gap: 5px;
  }

  .language-label-mobile {
    display: none !important;
  }

  .language-chevron {
    display: none !important;
  }

  .language-btn-mobile {
    width: 44px !important;
    padding: 0 !important;
    justify-content: center;
  }

  .header-icon-btn {
    width: 44px;
    height: 44px;
    min-width: 44px;
    min-height: 44px;
  }
}

@media (max-width: 390px) {
  .header-content-mobile {
    padding: 10px 8px;
    gap: 4px;
  }

  .logo-text-mobile {
    font-size: 16px;
  }

  .header-actions-mobile {
    gap: 4px;
  }

  .header-icon-btn {
    width: 40px;
    height: 40px;
    min-width: 40px;
    min-height: 40px;
  }

  .user-avatar-mobile {
    width: 32px;
    height: 32px;
    font-size: 12px;
  }

  .language-btn-mobile {
    width: 40px !important;
  }
}

web-frontend/src/App.css.content:
.app {
  min-height: 100vh;
  background-color: var(--bg-primary);
  position: relative;
}

.app::before {
  content: '';
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
