:root {
  --bg-primary: #0a0a0a;
  --bg-secondary: #1a1a1a;
  --bg-card: #242424;
  --bg-elevated: #2a2a2a;
  --text-primary: #f5f5f5;
  --text-secondary: #a8a8a8;
  --text-muted: #6b6b6b;
  --accent-primary: #d4a574;
  --accent-forest: #2d4a3e;
  --accent-lake: #4a7c9e;
  --diff-easy: #4caf50;
  --diff-medium: #ff9800;
  --diff-hard: #f44336;

  /* Layout & Z-Index System */
  --safe-top: env(safe-area-inset-top, 0px);
  --header-h: 64px;
  --z-navbar: 1000;
  --z-dropdown: 3000;
  --z-modal: 4000;
}

/* Sticky header - prevent margin collapsing */
header {
  position: sticky;
  top: 0;
  z-index: var(--z-navbar);
  margin: 0;
  padding: 0;
  overflow: visible;
}

/* Prevent gaps under header */
main,
.page-wrap,
.hero-section,
.page-hero {
  margin-top: 0 !important;
}

/* Ensure first child doesn't add stray margin */
main > *:first-child,
.page-wrap > *:first-child {
  margin-top: 0 !important;
}

* {
  box-sizing: border-box;
}

body {
  background-color: var(--bg-primary);
  background-image: 
    radial-gradient(circle at 10% 20%, rgba(212, 165, 116, 0.03) 0%, transparent 50%),
    radial-gradient(circle at 90% 80%, rgba(74, 124, 158, 0.03) 0%, transparent 50%);
  color: var(--text-primary);
  margin: 0;
  padding: 0;
  min-height: 100vh;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Roboto', 'Oxygen',
    'Ubuntu', 'Cantarell', 'Fira Sans', 'Droid Sans', 'Helvetica Neue',
    sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  position: relative;
}

body::before {
  content: '';
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background-image: url('data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" width="100" height="100"><path d="M0,50 Q25,40 50,50 T100,50" stroke="%23ffffff" stroke-width="0.5" fill="none" opacity="0.02"/><path d="M0,60 Q25,50 50,60 T100,60" stroke="%23ffffff" stroke-width="0.5" fill="none" opacity="0.02"/></svg>');
  background-size: 200px 200px;
  opacity: 0.3;
  pointer-events: none;
  z-index: 0;
}

.container {
  max-width: 1280px;
  margin: 0 auto;
  padding: 0 32px;
  position: relative;
  z-index: 1;
}

h1 {
  font-size: 36px;
  font-weight: 800;
  line-height: 1.2;
  margin: 0;
  letter-spacing: -0.5px;
}

h2 {
  font-size: 28px;
  font-weight: 700;
  line-height: 1.3;
  margin: 0;
  letter-spacing: -0.3px;
}

h3 {
  font-size: 22px;
  font-weight: 600;
  line-height: 1.4;
  margin: 0;
}

p {
  font-size: 16px;
  line-height: 1.7;
  margin: 0;
  font-weight: 400;
}

button {
  font-family: inherit;
  cursor: pointer;
  border: none;
  outline: none;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  position: relative;
  overflow: hidden;
}

button::before {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  width: 0;
  height: 0;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.1);
  transform: translate(-50%, -50%);
  transition: width 0.6s, height 0.6s;
}

button:active::before {
  width: 300px;
  height: 300px;
}

button:hover {
  transform: translateY(-2px);
}

button:active {
  transform: translateY(0);
}

input, select {
  font-family: inherit;
  font-size: 16px;
}

.btn-primary {
  background: linear-gradient(135deg, var(--accent-primary) 0%, #c49563 100%);
  color: #fff;
  padding: 16px 32px;
  border-radius: 16px;
  font-weight: 700;
  font-size: 16px;
  box-shadow: 0 4px 16px rgba(212, 165, 116, 0.3),
              inset 0 1px 0 rgba(255, 255, 255, 0.2);
  border: 1px solid rgba(255, 255, 255, 0.1);
  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.2);
}

.btn-primary:hover {
  box-shadow: 0 8px 24px rgba(212, 165, 116, 0.4),
              inset 0 1px 0 rgba(255, 255, 255, 0.3),
              0 0 20px rgba(212, 165, 116, 0.2);
  transform: translateY(-2px);
}

.btn-secondary {
  background: linear-gradient(145deg, rgba(42, 42, 42, 0.8), rgba(36, 36, 36, 0.6));
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  color: var(--text-primary);
  padding: 16px 32px;
  border-radius: 16px;
  font-weight: 600;
  font-size: 16px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.2);
}

.btn-secondary:hover {
  background: linear-gradient(145deg, rgba(50, 50, 50, 0.9), rgba(40, 40, 40, 0.7));
  border-color: rgba(212, 165, 116, 0.3);
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.3);
}

.card {
  background: linear-gradient(145deg, rgba(36, 36, 36, 0.9), rgba(26, 26, 26, 0.8));
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.05);
  border-radius: 20px;
  padding: 24px;
  margin-bottom: 20px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3),
              inset 0 1px 0 rgba(255, 255, 255, 0.05);
}

.badge {
  display: inline-block;
  padding: 6px 16px;
  border-radius: 16px;
  font-size: 13px;
  font-weight: 700;
  text-transform: capitalize;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
  letter-spacing: 0.3px;
}

.badge-easy { 
  background: linear-gradient(135deg, var(--diff-easy) 0%, #45a049 100%);
  color: #fff;
  box-shadow: 0 2px 8px rgba(76, 175, 80, 0.4);
}

.badge-medium { 
  background: linear-gradient(135deg, var(--diff-medium) 0%, #f57c00 100%);
  color: #fff;
  box-shadow: 0 2px 8px rgba(255, 152, 0, 0.4);
}

.badge-hard { 
  background: linear-gradient(135deg, var(--diff-hard) 0%, #e53935 100%);
  color: #fff;
  box-shadow: 0 2px 8px rgba(244, 67, 54, 0.4);
}

@media (max-width: 768px) {
  .container {
    padding: 0 20px;
  }

  h1 {
    font-size: 28px;
  }

  h2 {
    font-size: 24px;
  }
}

