.media-gallery {
  margin-top: 40px;
}

.media-gallery-header {
  margin-bottom: 30px;
}

.media-tabs {
  display: flex;
  gap: 12px;
  margin-top: 20px;
}

.media-tab {
  padding: 12px 24px;
