  -webkit-backdrop-filter: blur(10px);
  border-radius: 12px;
  color: #d4a574;
  font-size: 16px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  border: 1px solid rgba(212, 165, 116, 0.2);
}

.media-tab:hover:not(:disabled) {
