}

.media-content {
  min-height: 300px;
}

.photo-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 20px;
}

.photo-card {
  position: relative;
  border-radius: 16px;
  overflow: hidden;
  cursor: pointer;
  aspect-ratio: 4/3;
  background: rgba(255, 255, 255, 0.03);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: all 0.3s ease;
}

.photo-card:hover {
  transform: translateY(-8px) scale(1.02);
  box-shadow: 0 12px 40px rgba(212, 165, 116, 0.3);
  border-color: rgba(212, 165, 116, 0.4);
}

.photo-card img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.photo-overlay {
  position: absolute;
  inset: 0;
  background: linear-gradient(to top, rgba(0,0,0,0.7) 0%, transparent 50%);
  opacity: 0;
  transition: opacity 0.3s ease;
  display: flex;
  align-items: center;
  justify-content: center;
}

.photo-card:hover .photo-overlay {
  opacity: 1;
}

.photo-expand-icon {
  font-size: 48px;
  filter: drop-shadow(0 2px 8px rgba(0,0,0,0.5));
}

.media-empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 80px 20px;
  background: rgba(255, 255, 255, 0.03);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border-radius: 20px;
  border: 1px solid rgba(255, 255, 255, 0.1);
}

.empty-icon {
  font-size: 64px;
  margin-bottom: 20px;
  opacity: 0.5;
}

.media-empty p {
  color: #999;
  font-size: 16px;
}

/* Lightbox */
.lightbox-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.95);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  z-index: 9999;
  display: flex;
  align-items: center;
  justify-content: center;
  animation: fadeIn 0.3s ease;
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

.lightbox-content {
  position: relative;
  max-width: 90vw;
  max-height: 90vh;
  display: flex;
  align-items: center;
  justify-content: center;
}

.lightbox-content img {
  max-width: 100%;
  max-height: 90vh;
  object-fit: contain;
  border-radius: 8px;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.8);
}

.lightbox-close {
  position: absolute;
  top: -50px;
  right: 0;
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.2);
  border-radius: 50%;
  width: 48px;
  height: 48px;
  color: white;
  font-size: 24px;
  cursor: pointer;
  transition: all 0.3s ease;
  display: flex;
  align-items: center;
  justify-content: center;
}

.lightbox-close:hover {
  background: rgba(255, 255, 255, 0.2);
  transform: rotate(90deg);
}

.lightbox-nav {
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.2);
  border-radius: 50%;
  width: 56px;
  height: 56px;
  color: white;
  font-size: 36px;
  cursor: pointer;
  transition: all 0.3s ease;
  display: flex;
  align-items: center;
  justify-content: center;
}

.lightbox-nav:hover {
  background: rgba(212, 165, 116, 0.3);
  border-color: rgba(212, 165, 116, 0.5);
  transform: translateY(-50%) scale(1.1);
}

.lightbox-prev {
  left: -80px;
}

.lightbox-next {
  right: -80px;
}

.lightbox-counter {
  position: absolute;
  bottom: -50px;
  left: 50%;
  transform: translateX(-50%);
  color: white;
  font-size: 16px;
  font-weight: 600;
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  padding: 10px 20px;
  border-radius: 20px;
  border: 1px solid rgba(255, 255, 255, 0.2);
}

/* Mobile responsiveness */
@media (max-width: 768px) {
  .photo-grid {
    grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
    gap: 15px;
  }

  .media-tabs {
    flex-direction: column;
  }

  .media-tab {
    width: 100%;
  }

  .lightbox-nav {
    width: 44px;
    height: 44px;
    font-size: 28px;
  }

  .lightbox-prev {
    left: 10px;
  }

  .lightbox-next {
    right: 10px;
  }

  .lightbox-close {
    top: 10px;
    right: 10px;
  }

  .lightbox-counter {
    bottom: 10px;
  }
}

@media (max-width: 480px) {
  .photo-grid {
    grid-template-columns: 1fr;
  }
}

web-frontend/src/components/FeaturedCaro.content:
import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import './FeaturedCarousel.css';

function FeaturedCarousel({ trails, onViewTrail }) {
  const { t } = useTranslation();
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isAutoPlaying, setIsAutoPlaying] = useState(true);

  useEffect(() => {
    if (!isAutoPlaying || !trails || trails.length === 0) return;

    const interval = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % trails.length);
    }, 5000);

    return () => clearInterval(interval);
  }, [isAutoPlaying, trails]);

  if (!trails || trails.length === 0) return null;

  const nextSlide = () => {
    setIsAutoPlaying(false);
    setCurrentIndex((prev) => (prev + 1) % trails.length);
  };

  const prevSlide = () => {
    setIsAutoPlaying(false);
    setCurrentIndex((prev) => (prev - 1 + trails.length) % trails.length);
  };

  const goToSlide = (index) => {
    setIsAutoPlaying(false);
    setCurrentIndex(index);
  };

  const currentTrail = trails[currentIndex];

  return (
    <div className="featured-carousel">
      <div className="carousel-container">
        <div className="carousel-slide">
          <div className="carousel-hero-section">
            <img 
              src={currentTrail.image_url} 
              alt={`${currentTrail.name} - ${currentTrail.region}`}
              className="carousel-hero-image"
            />
            <div className="carousel-hero-gradient"></div>
            <span className="region-badge-floating">{currentTrail.region}</span>

            <button 
              className="carousel-nav carousel-prev" 
              onClick={prevSlide}
              aria-label={t('home.previousTrail') || 'Previous trail'}
            >
              ‹
            </button>
            <button 
              className="carousel-nav carousel-next" 
              onClick={nextSlide}
              aria-label={t('home.nextTrail') || 'Next trail'}
            >
              ›
            </button>
          </div>

          <div className="carousel-glass-panel">
            <div className="carousel-info">
              <h2 className="carousel-title">{currentTrail.name}</h2>
              <p className="carousel-tagline">{currentTrail.tagline}</p>
            </div>

            <div className="carousel-stats-grid">
              <div className="stat-chip">
                <span className="stat-icon">📏</span>
                <div className="stat-content">
                  <span className="stat-value">{currentTrail.distance_km}</span>
                  <span className="stat-unit">km</span>
                </div>
              </div>
              <div className="stat-chip">
                <span className="stat-icon">⏱️</span>
                <div className="stat-content">
                  <span className="stat-value">{currentTrail.duration_hours}</span>
                  <span className="stat-unit">h</span>
                </div>
              </div>
              <div className="stat-chip">
                <span className="stat-icon">⛰️</span>
                <div className="stat-content">
                  <span className="stat-value">{currentTrail.elevation_gain_m}</span>
                  <span className="stat-unit">m</span>
                </div>
              </div>
              <div className={`stat-chip difficulty-chip difficulty-${currentTrail.difficulty}`}>
                <span className="difficulty-label">{t(`catalog.${currentTrail.difficulty}`)}</span>
              </div>
            </div>

            <button className="carousel-cta-pill" onClick={() => onViewTrail(currentTrail)}>
              <span className="cta-text">{t('home.exploreTrail')}</span>
              <span className="cta-arrow">→</span>
            </button>
          </div>
        </div>
      </div>

      <div className="carousel-aurora-indicators">
        {trails.map((trail, index) => (
          <button
            key={index}
            className={`aurora-dot ${index === currentIndex ? 'active' : ''}`}
            onClick={() => goToSlide(index)}
            aria-label={`${t('home.goTo') || 'Go to'} ${trail.name}`}
          />
        ))}
      </div>
    </div>
  );
}

export default FeaturedCarousel;

