  display: flex;
  flex-direction: column;
  gap: 0.75rem;
  margin-bottom: 1.5rem;
}

.selected-trail-item {
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(212, 165, 116, 0.2);
  border-radius: 8px;
  padding: 0.75rem;
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.trail-order {
  background: rgba(212, 165, 116, 0.2);
  color: #d4a574;
  width: 28px;
  height: 28px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 600;
  flex-shrink: 0;
}

.trail-info-compact {
  flex: 1;
}

.trail-info-compact h4 {
  color: #fff;
  font-size: 0.9rem;
  margin-bottom: 0.25rem;
}

.trail-stats-compact {
  color: rgba(255, 255, 255, 0.6);
  font-size: 0.75rem;
}

.btn-remove-trail {
  background: transparent;
  border: 1px solid rgba(244, 67, 54, 0.3);
  color: #e57373;
  width: 28px;
  height: 28px;
  border-radius: 50%;
  cursor: pointer;
  font-size: 1.2rem;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.3s ease;
