}

.saved-list {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.saved-item {
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(212, 165, 116, 0.2);
  border-radius: 8px;
  padding: 0.75rem;
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 0.75rem;
}

.saved-info h4 {
  color: #fff;
  font-size: 0.9rem;
  margin-bottom: 0.25rem;
}

.saved-meta {
