  border: 1px solid rgba(212, 165, 116, 0.3);
  border-radius: 12px;
  padding: 2rem;
  max-width: 500px;
  width: 100%;
}

.modal-content h3 {
  color: #d4a574;
  font-size: 1.5rem;
  margin-bottom: 1.5rem;
}

.modal-input {
  width: 100%;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(212, 165, 116, 0.3);
  border-radius: 8px;
  padding: 0.875rem;
  color: #fff;
  font-size: 1rem;
  margin-bottom: 1.5rem;
}

.modal-input:focus {
  outline: none;
  border-color: #d4a574;
  background: rgba(255, 255, 255, 0.08);
}

.modal-actions {
  display: flex;
  gap: 1rem;
  justify-content: flex-end;
}

.export-modal {
  max-width: 600px;
}

.export-textarea {
  width: 100%;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(212, 165, 116, 0.3);
  border-radius: 8px;
  padding: 1rem;
  color: #fff;
  font-family: 'Courier New', monospace;
  font-size: 0.9rem;
  margin-bottom: 1.5rem;
  resize: vertical;
}

.export-textarea:focus {
  outline: none;
  border-color: #d4a574;
}

@media (max-width: 1024px) {
  .planner-grid {
    grid-template-columns: 1fr;
  }

  .planner-sidebar {
    position: static;
  }
}

@media (max-width: 768px) {
  .planner-page {
    padding-top: calc(var(--safe-top) + var(--header-h) + 16px);
    padding-left: 0;
    padding-right: 0;
    padding-bottom: 2rem;
  }

  .back-button {
    margin-bottom: 1.5rem;
    margin-left: 1rem;
    margin-right: 1rem;
    padding: 12px 20px;
    font-size: 14px;
  }

  .planner-title {
    font-size: 1.75rem;
  }

  .date-selector {
    grid-template-columns: 1fr;
  }

  .trail-selection-grid {
    grid-template-columns: 1fr;
  }

  .planner-section {
    padding: 1.5rem;
  }

  .planner-btn,
  .add-trail-btn,
  .export-btn,
  .save-btn,
  .clear-btn {
    min-height: 48px;
    min-width: 48px;
    padding: 14px 24px;
    font-size: 15px;
  }

  .planner-form input,
  .planner-form select,
  .planner-form textarea {
    min-height: 48px;
    font-size: 16px;
    padding: 12px 16px;
  }

  .trail-selection-card {
    padding: 1rem;
  }

  .itinerary-actions {
    flex-direction: column;
    gap: 12px;
  }

  .itinerary-actions button {
    width: 100%;
  }
}

@media (max-width: 480px) {
  .planner-title {
    font-size: 1.5rem;
  }

  .planner-section {
    padding: 1rem;
  }
}

