    opacity: 0;
  }
}

/* 3D Hiking Poles Animation */
.poles-container {
  position: relative;
  height: 200px;
  margin-bottom: 2rem;
  z-index: 2;
}

.pole {
  position: absolute;
  top: 50%;
  transform-style: preserve-3d;
  animation: pole-swing 2s ease-in-out infinite;
}

.pole-left {
  left: 30%;
  transform: translate(-50%, -50%) rotate(-30deg);
}

.pole-right {
  right: 30%;
  transform: translate(50%, -50%) rotate(30deg);
  animation-delay: 0.5s;
}

@keyframes pole-swing {
  0%, 100% {
    transform: translate(-50%, -50%) rotate(-30deg);
  }
  50% {
    transform: translate(-50%, -50%) rotate(-45deg) translateY(-10px);
  }
}

.pole.pole-right {
  animation-name: pole-swing-right;
}

@keyframes pole-swing-right {
  0%, 100% {
    transform: translate(50%, -50%) rotate(30deg);
  }
  50% {
    transform: translate(50%, -50%) rotate(45deg) translateY(-10px);
  }
}

.pole-shaft {
  width: 8px;
  height: 150px;
  background: linear-gradient(135deg, #8b7355 0%, #6b5a45 100%);
  border-radius: 4px;
  box-shadow: 
    inset -2px 0 4px rgba(0, 0, 0, 0.3),
    2px 2px 8px rgba(0, 0, 0, 0.5);
  position: relative;
}

.pole-grip {
  position: absolute;
  top: 20px;
  left: -4px;
  width: 16px;
  height: 40px;
  background: linear-gradient(135deg, #2d4a3e 0%, #1a2f26 100%);
  border-radius: 8px;
  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.4);
}

.pole-tip {
  position: absolute;
  bottom: -8px;
  left: 50%;
  transform: translateX(-50%);
  width: 0;
  height: 0;
  border-left: 6px solid transparent;
  border-right: 6px solid transparent;
  border-top: 12px solid #d4a574;
  filter: drop-shadow(0 2px 4px rgba(0, 0, 0, 0.5));
}

.celebration-modal.poles-cross .pole-left {
  animation: cross-left 1s ease-out forwards;
}

.celebration-modal.poles-cross .pole-right {
  animation: cross-right 1s ease-out forwards;
}

@keyframes cross-left {
  to {
    transform: translate(-50%, -50%) rotate(45deg) scale(1.1);
  }
}

@keyframes cross-right {
  to {
    transform: translate(50%, -50%) rotate(-45deg) scale(1.1);
  }
}

/* Congratulations Message */
.congrats-message {
  text-align: center;
  margin-bottom: 2rem;
  z-index: 2;
  position: relative;
}

.congrats-title {
  font-size: 2rem;
  font-weight: 900;
  background: linear-gradient(135deg, #d4a574 0%, #4a7c9e 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: 0.5rem;
  text-shadow: 0 4px 8px rgba(212, 165, 116, 0.3);
  animation: pulse-glow 2s ease-in-out infinite;
}

@keyframes pulse-glow {
  0%, 100% {
    filter: drop-shadow(0 0 10px rgba(212, 165, 116, 0.5));
  }
  50% {
    filter: drop-shadow(0 0 20px rgba(212, 165, 116, 0.8));
  }
}

.congrats-subtitle {
  font-size: 1.2rem;
  color: rgba(255, 255, 255, 0.9);
  margin-bottom: 0.5rem;
}

.trail-name {
  font-size: 1.4rem;
  font-weight: 700;
  color: #d4a574;
  margin-top: 0.5rem;
}

/* Stats Summary */
.stats-summary {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(100px, 1fr));
  gap: 1rem;
  margin-bottom: 2rem;
  z-index: 2;
  position: relative;
}

.stat-card {
  background: rgba(212, 165, 116, 0.1);
  border: 2px solid rgba(212, 165, 116, 0.3);
  border-radius: 16px;
  padding: 1rem;
  text-align: center;
  transition: all 0.3s ease;
  animation: stat-pop 0.6s ease backwards;
}

.stat-card:nth-child(1) { animation-delay: 0.1s; }
.stat-card:nth-child(2) { animation-delay: 0.2s; }
.stat-card:nth-child(3) { animation-delay: 0.3s; }
.stat-card:nth-child(4) { animation-delay: 0.4s; }

@keyframes stat-pop {
  from {
    transform: scale(0) rotate(-180deg);
    opacity: 0;
  }
  to {
    transform: scale(1) rotate(0deg);
    opacity: 1;
  }
}

.stat-card:hover {
  transform: translateY(-4px) scale(1.05);
  border-color: #d4a574;
  box-shadow: 0 8px 24px rgba(212, 165, 116, 0.3);
}

.stat-icon {
  font-size: 2rem;
  margin-bottom: 0.5rem;
}

.stat-value {
  font-size: 1.5rem;
  font-weight: 800;
  color: #d4a574;
  margin-bottom: 0.25rem;
}

.stat-label {
  font-size: 0.85rem;
  color: rgba(255, 255, 255, 0.7);
  text-transform: uppercase;
  letter-spacing: 1px;
}

.xp-card {
  background: linear-gradient(135deg, rgba(212, 165, 116, 0.2) 0%, rgba(74, 124, 158, 0.2) 100%);
  border-color: #d4a574;
}

/* Badges Earned */
.badges-earned {
  background: rgba(45, 74, 62, 0.3);
  border: 2px solid rgba(74, 124, 158, 0.5);
  border-radius: 16px;
  padding: 1.5rem;
  margin-bottom: 2rem;
  z-index: 2;
  position: relative;
  animation: badge-reveal 0.8s ease 1s backwards;
}

@keyframes badge-reveal {
  from {
    transform: rotateX(-90deg);
    opacity: 0;
  }
  to {
    transform: rotateX(0deg);
    opacity: 1;
  }
}

.badges-earned h3 {
  text-align: center;
  color: #d4a574;
  margin-bottom: 1rem;
  font-size: 1.3rem;
}

.badge-list {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.badge-item {
  display: flex;
  align-items: center;
  gap: 1rem;
  background: rgba(212, 165, 116, 0.1);
  padding: 0.75rem;
  border-radius: 12px;
  transition: all 0.3s ease;
}

.badge-item:hover {
  background: rgba(212, 165, 116, 0.2);
  transform: translateX(8px);
}

.badge-icon {
  font-size: 2rem;
}

.badge-name {
  font-size: 1rem;
  font-weight: 600;
  color: white;
}

/* Checkpoints Visited */
.checkpoints-visited {
  background: rgba(74, 222, 128, 0.15);
  border: 2px solid rgba(74, 222, 128, 0.4);
  border-radius: 16px;
  padding: 1.5rem;
  margin-bottom: 2rem;
  z-index: 2;
  position: relative;
  animation: checkpoint-reveal 0.8s ease 1.2s backwards;
}

@keyframes checkpoint-reveal {
  from {
    transform: translateY(20px);
    opacity: 0;
  }
  to {
    transform: translateY(0);
    opacity: 1;
  }
}

.checkpoints-visited h3 {
  text-align: center;
  color: #4ade80;
  margin-bottom: 1rem;
  font-size: 1.3rem;
}

.checkpoint-list {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.checkpoint-item {
  display: flex;
  align-items: center;
  gap: 1rem;
  background: rgba(74, 222, 128, 0.1);
  padding: 0.75rem;
  border-radius: 12px;
  transition: all 0.3s ease;
  border-left: 3px solid rgba(74, 222, 128, 0.5);
}

.checkpoint-item:hover {
  background: rgba(74, 222, 128, 0.2);
  transform: translateX(8px);
  border-left-color: #4ade80;
}

.checkpoint-icon {
  font-size: 1.5rem;
}

.checkpoint-name {
  font-size: 1rem;
  font-weight: 600;
  color: white;
}

/* Close Button */
.celebration-close-btn {
  width: 100%;
  padding: 1rem;
  background: linear-gradient(135deg, #d4a574 0%, #a67c52 100%);
