import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import axios from 'axios';
import './MultiDayTrailDetail.css';

const API_URL = import.meta.env.VITE_API_URL || (typeof window !== 'undefined' && window.location.origin.includes('replit') 
  ? `https://${window.location.host.split('--')[0].replace(/^webview-/, '')}--8000.${window.location.host.split('.').slice(1).join('.')}` 
  : 'http://localhost:8000');

function MultiDayTrailDetail({ trailId, onNavigate }) {
  const { t } = useTranslation();
  const [trail, setTrail] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeStage, setActiveStage] = useState(1);
  const [showEquipment, setShowEquipment] = useState(false);

  useEffect(() => {
    fetchTrailDetail();
  }, [trailId]);

  const fetchTrailDetail = async () => {
    try {
      setLoading(true);
      const response = await axios.get(`${API_URL}/api/multi-day-trails/${trailId}`);
      setTrail(response.data);
    } catch (error) {
      console.error('Error fetching trail detail:', error);
    } finally {
      setLoading(false);
    }
  };

  const getDifficultyColor = (difficulty) => {
    const colors = {
      easy: '#4caf50',
      moderate: '#ff9800',
      challenging: '#f44336',
      expert: '#9c27b0'
    };
    return colors[difficulty] || '#999';
  };

  if (loading) {
    return (
      <div className="multiday-detail-loading">
        <div className="loading-spinner"></div>
        <p>{t('common.loading')}</p>
      </div>
    );
  }

  if (!trail) {
    return (
      <div className="multiday-detail-error">
        <h2>{t('multiday.notFound', 'Trail not found')}</h2>
        <button onClick={() => onNavigate('multiday-trails')}>
          {t('multiday.backToList', 'Back to Trails')}
        </button>
      </div>
    );
  }

  const currentStage = trail.stages?.[activeStage - 1];

  return (
    <div className="multiday-detail-page">
      {/* Hero Section */}
      <div 
        className="multiday-detail-hero"
        style={{ backgroundImage: `url(${trail.hero_image || 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=1600'})` }}
      >
        <div className="multiday-detail-hero-overlay"></div>
        <div className="multiday-detail-hero-content">
          <button className="back-btn" onClick={() => onNavigate('multiday-trails')}>
            ← {t('common.back', 'Back')}
          </button>
          <h1 className="multiday-detail-title">{trail.name}</h1>
          <div className="multiday-detail-meta">
            <span className="meta-item">📍 {trail.region}</span>
            <span className="meta-item">📅 {trail.duration_days}D/{trail.duration_nights}N</span>
            <span className="meta-item">📏 {trail.total_distance_km} km</span>
            <span className="meta-item">⛰️ {trail.total_elevation_gain_m} m ↑</span>
            <span 
              className="meta-item difficulty-badge"
              style={{ 
                background: getDifficultyColor(trail.difficulty) + '20',
                color: getDifficultyColor(trail.difficulty)
              }}
            >
              {t(`difficulty.${trail.difficulty}`, trail.difficulty)}
            </span>
          </div>
        </div>
      </div>

      <div className="multiday-detail-container">
        {/* Overview Section */}
        <div className="detail-section overview-section">
          <h2>{t('multiday.overview', 'Trek Overview')}</h2>
          <p className="overview-description">{trail.description}</p>

          {trail.highlights && trail.highlights.length > 0 && (
            <div className="highlights-grid">
              {trail.highlights.map((highlight, index) => (
                <div key={index} className="highlight-item">
                  <span className="highlight-icon">✨</span>
                  <span>{highlight}</span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Stages Section */}
        <div className="detail-section stages-section">
          <h2>{t('multiday.stages', 'Trek Stages')} ({trail.stages?.length || 0} {t('multiday.days', 'days')})</h2>

          {/* Stage Navigation */}
          <div className="stages-nav">
            {trail.stages?.map((stage, index) => (
              <button
                key={index}
                className={`stage-nav-btn ${activeStage === stage.stage_number ? 'active' : ''}`}
                onClick={() => setActiveStage(stage.stage_number)}
              >
                <div className="stage-nav-number">{t('multiday.day', 'Day')} {stage.stage_number}</div>
                <div className="stage-nav-name">{stage.name}</div>
                <div className="stage-nav-stats">
                  {stage.distance_km} km · {stage.estimated_duration_hours}h
                </div>
              </button>
            ))}
          </div>

          {/* Active Stage Detail */}
          {currentStage && (
            <div className="stage-detail-card">
              <div className="stage-detail-header">
                <div>
                  <h3>
                    {t('multiday.day', 'Day')} {currentStage.stage_number}: {currentStage.name}
                  </h3>
                  <p className="stage-description">{currentStage.description}</p>
                </div>
                <div 
                  className="stage-difficulty-badge"
                  style={{ 
                    background: getDifficultyColor(currentStage.difficulty) + '20',
                    color: getDifficultyColor(currentStage.difficulty)
                  }}
                >
                  {t(`difficulty.${currentStage.difficulty}`, currentStage.difficulty)}
                </div>
              </div>

              <div className="stage-stats-grid">
                <div className="stage-stat">
                  <div className="stage-stat-icon">📏</div>
                  <div className="stage-stat-content">
                    <div className="stage-stat-label">{t('multiday.distance', 'Distance')}</div>
                    <div className="stage-stat-value">{currentStage.distance_km} km</div>
                  </div>
                </div>
                <div className="stage-stat">
                  <div className="stage-stat-icon">⬆️</div>
                  <div className="stage-stat-content">
                    <div className="stage-stat-label">{t('multiday.elevationGain', 'Elevation Gain')}</div>
                    <div className="stage-stat-value">{currentStage.elevation_gain_m} m</div>
                  </div>
                </div>
                <div className="stage-stat">
                  <div className="stage-stat-icon">⬇️</div>
                  <div className="stage-stat-content">
                    <div className="stage-stat-label">{t('multiday.elevationLoss', 'Elevation Loss')}</div>
                    <div className="stage-stat-value">{currentStage.elevation_loss_m} m</div>
                  </div>
                </div>
                <div className="stage-stat">
                  <div className="stage-stat-icon">⏱️</div>
                  <div className="stage-stat-content">
                    <div className="stage-stat-label">{t('multiday.duration', 'Duration')}</div>
                    <div className="stage-stat-value">{currentStage.estimated_duration_hours}h</div>
                  </div>
                </div>
              </div>

              {/* Route Points */}
              <div className="route-points">
                <div className="route-point">
                  <div className="route-point-icon start">🚀</div>
                  <div className="route-point-content">
                    <div className="route-point-label">{t('multiday.start', 'Start')}</div>
                    <div className="route-point-name">{currentStage.start_point?.name}</div>
                    <div className="route-point-elevation">{currentStage.start_point?.elevation_m} m</div>
                  </div>
                </div>
                <div className="route-connector"></div>
                <div className="route-point">
                  <div className="route-point-icon end">🏁</div>
                  <div className="route-point-content">
                    <div className="route-point-label">{t('multiday.end', 'End')}</div>
                    <div className="route-point-name">{currentStage.end_point?.name}</div>
                    <div className="route-point-elevation">{currentStage.end_point?.elevation_m} m</div>
                  </div>
                </div>
              </div>

              {/* Overnight Rifugio */}
              {currentStage.overnight_rifugio_name && (
                <div className="overnight-rifugio">
                  <h4>🏔️ {t('multiday.overnightStay', 'Overnight Stay')}</h4>
                  <div className="rifugio-card">
                    <div className="rifugio-info">
                      <div className="rifugio-name">{currentStage.overnight_rifugio_name}</div>
                      {currentStage.overnight_rifugio_details && (
                        <div className="rifugio-details">
                          <span>📍 {currentStage.overnight_rifugio_details.altitude} m</span>
                          <span>🛏️ {currentStage.overnight_rifugio_details.beds} {t('multiday.beds', 'beds')}</span>
                          {currentStage.overnight_rifugio_details.contact && (
                            <span>📞 {currentStage.overnight_rifugio_details.contact}</span>
                          )}
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              )}

              {/* Stage Highlights */}
              {currentStage.highlights && currentStage.highlights.length > 0 && (
                <div className="stage-highlights">
                  <h4>{t('multiday.highlights', 'Stage Highlights')}</h4>
                  <ul>
                    {currentStage.highlights.map((highlight, index) => (
                      <li key={index}>{highlight}</li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
          )}
        </div>

        {/* Equipment & Planning Section */}
        <div className="detail-section planning-section">
          <div className="planning-header">
            <h2>{t('multiday.planning', 'Trip Planning')}</h2>
            <button 
              className="equipment-toggle-btn"
              onClick={() => setShowEquipment(!showEquipment)}
            >
              {showEquipment ? '▼' : '▶'} {t('multiday.equipmentChecklist', 'Equipment Checklist')}
            </button>
          </div>

          {showEquipment && trail.equipment_checklist && (
            <div className="equipment-checklist">
              <div className="checklist-grid">
                {trail.equipment_checklist.map((item, index) => (
                  <div key={index} className="checklist-item">
                    <span className="checklist-checkbox">☐</span>
                    <span>{item}</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Booking Tips */}
          {trail.booking_tips && trail.booking_tips.length > 0 && (
            <div className="booking-tips">
              <h4>💡 {t('multiday.bookingTips', 'Booking Tips')}</h4>
              <ul>
                {trail.booking_tips.map((tip, index) => (
                  <li key={index}>{tip}</li>
                ))}
              </ul>
            </div>
          )}

          {/* Season Info */}
          <div className="season-info">
            <h4>📅 {t('multiday.bestSeason', 'Best Season')}</h4>
            <p>
              {trail.best_season_start && trail.best_season_end && (
                <>
                  {new Date(`2000-${trail.best_season_start}`).toLocaleDateString('en', { month: 'long', day: 'numeric' })}
                  {' - '}
                  {new Date(`2000-${trail.best_season_end}`).toLocaleDateString('en', { month: 'long', day: 'numeric' })}
                </>
              )}
            </p>
          </div>
        </div>

        {/* Gallery */}
        {trail.photos && trail.photos.length > 0 && (
          <div className="detail-section gallery-section">
            <h2>{t('multiday.gallery', 'Trail Gallery')}</h2>
            <div className="photos-grid">
              {trail.photos.map((photo, index) => (
                <div key={index} className="photo-item">
                  <img src={photo} alt={`${trail.name} - ${index + 1}`} loading="lazy" />
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Call to Action */}
        <div className="detail-section cta-section">
          <h3>{t('multiday.readyToStart', 'Ready to Start Your Adventure?')}</h3>
          <p>{t('multiday.ctaDescription', 'Plan your multi-day trek and book your rifugio stays in advance')}</p>
          <div className="cta-buttons">
            <button 
              className="cta-btn primary"
              onClick={() => onNavigate('rifugios')}
            >
              🏔️ {t('multiday.browseRifugios', 'Browse Rifugios')}
            </button>
            <button 
              className="cta-btn secondary"
              onClick={() => onNavigate('hike-planner')}
            >
              📋 {t('multiday.addToPlanner', 'Add to Planner')}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

export default MultiDayTrailDetail;

web-frontend/src/components/admin/MultiD.content:
import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import axios from 'axios';
import './MultiDayTrailsManager.css';

const API_URL = import.meta.env.VITE_API_URL || (typeof window !== 'undefined' && window.location.origin.includes('replit') 
  ? `https://${window.location.host.split('--')[0].replace(/^webview-/, '')}--8000.${window.location.host.split('.').slice(1).join('.')}` 
  : 'http://localhost:8000');

function MultiDayTrailsManager({ adminPassword }) {
  const { t } = useTranslation();
  const [trails, setTrails] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [editingTrail, setEditingTrail] = useState(null);
  const [isCreating, setIsCreating] = useState(false);
  const [successMessage, setSuccessMessage] = useState('');

  useEffect(() => {
    fetchTrails();
  }, []);

  const fetchTrails = async () => {
    try {
      setLoading(true);
      const response = await axios.get(`${API_URL}/api/admin/multi-day-trails`, {
        headers: { 'X-Admin-Password': adminPassword }
      });
      setTrails(response.data.trails || []);
      setError(null);
    } catch (err) {
      setError(t('admin.failedToLoadMultiDay') + ': ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleCreateNew = () => {
    const newTrail = {
      id: '',
      name: '',
      description: '',
      type: 'point-to-point',
      duration_days: 3,
      duration_nights: 2,
      total_distance_km: 0,
      total_elevation_gain_m: 0,
      total_elevation_loss_m: 0,
      difficulty: 'moderate',
      best_season_start: '06-01',
      best_season_end: '09-30',
      region: 'Dolomites',
      hero_image: '',
      thumbnail: '',
      photos: [],
      highlights: [],
      tags: [],
      rifugio_ids: [],
      stages: [],
      equipment_checklist: [],
      booking_tips: [],
      status: 'draft'
    };
    setEditingTrail(newTrail);
    setIsCreating(true);
  };

  const handleSave = async () => {
    try {
      // Validate required fields
      if (!editingTrail.id || !editingTrail.name) {
        setError(t('admin.trailIdRequired'));
        return;
      }

      // Calculate totals from stages
      const totalDistance = editingTrail.stages.reduce((sum, s) => sum + (parseFloat(s.distance_km) || 0), 0);
      const totalElevGain = editingTrail.stages.reduce((sum, s) => sum + (parseInt(s.elevation_gain_m) || 0), 0);
      const totalElevLoss = editingTrail.stages.reduce((sum, s) => sum + (parseInt(s.elevation_loss_m) || 0), 0);

      const trailToSave = {
        ...editingTrail,
        total_distance_km: totalDistance,
        total_elevation_gain_m: totalElevGain,
        total_elevation_loss_m: totalElevLoss
      };

      if (isCreating) {
        await axios.post(`${API_URL}/api/admin/multi-day-trails`, trailToSave, {
          headers: { 'X-Admin-Password': adminPassword }
        });
        setSuccessMessage(t('admin.trailCreatedSuccess'));
      } else {
        await axios.put(`${API_URL}/api/admin/multi-day-trails/${editingTrail.id}`, trailToSave, {
          headers: { 'X-Admin-Password': adminPassword }
        });
        setSuccessMessage(t('admin.trailUpdatedSuccess'));
      }

      await fetchTrails();
      setEditingTrail(null);
      setIsCreating(false);
      setTimeout(() => setSuccessMessage(''), 3000);
    } catch (err) {
      setError(t('admin.failedToSaveTrail') + ': ' + err.message);
    }
  };

  const handleDelete = async (trailId) => {
    if (!confirm(t('admin.confirmDelete'))) {
      return;
    }

    try {
      await axios.delete(`${API_URL}/api/admin/multi-day-trails/${trailId}`, {
        headers: { 'X-Admin-Password': adminPassword }
      });
      setSuccessMessage(t('admin.trailDeletedSuccess'));
      await fetchTrails();
      setTimeout(() => setSuccessMessage(''), 3000);
    } catch (err) {
      setError(t('admin.failedToDeleteTrail') + ': ' + err.message);
    }
  };

  const handleAddStage = () => {
    const newStage = {
      stage_number: editingTrail.stages.length + 1,
      name: '',
      description: '',
      distance_km: 0,
      elevation_gain_m: 0,
      elevation_loss_m: 0,
      estimated_duration_hours: 5,
      difficulty: 'moderate',
      start_point: { name: '', lat: 0, lon: 0, elevation_m: 0 },
      end_point: { name: '', lat: 0, lon: 0, elevation_m: 0 },
      overnight_rifugio_name: '',
      overnight_rifugio_details: null,
      waypoints: [],
      highlights: [],
      photos: []
    };

    setEditingTrail({
      ...editingTrail,
      stages: [...editingTrail.stages, newStage]
    });
  };

  const handleRemoveStage = (index) => {
    const newStages = editingTrail.stages.filter((_, i) => i !== index);
    // Renumber stages
    newStages.forEach((stage, i) => {
      stage.stage_number = i + 1;
    });
    setEditingTrail({
      ...editingTrail,
      stages: newStages
    });
  };

  const updateStage = (index, field, value) => {
    const newStages = [...editingTrail.stages];
    newStages[index] = { ...newStages[index], [field]: value };
    setEditingTrail({
      ...editingTrail,
      stages: newStages
    });
  };

  const updateField = (field, value) => {
    setEditingTrail({ ...editingTrail, [field]: value });
  };

  if (loading) {
    return <div className="multiday-manager-loading">{t('admin.loadingMultiDayTrails')}</div>;
  }

  return (
    <div className="multiday-trails-manager">
      <div className="multiday-header">
        <h2>🏔️ {t('multiday.availableTrails')}</h2>
        <button className="create-btn" onClick={handleCreateNew}>
          + {t('admin.createNewTrail')}
        </button>
      </div>

      {error && (
        <div className="error-message">
          {error}
          <button onClick={() => setError(null)}>×</button>
        </div>
      )}

      {successMessage && (
        <div className="success-message">
          {successMessage}
        </div>
      )}

      {!editingTrail && (
        <div className="trails-list">
          <table className="trails-table">
            <thead>
              <tr>
                <th>ID</th>
                <th>{t('admin.trailName')}</th>
                <th>{t('multiday.days')}</th>
                <th>{t('multiday.stages')}</th>
                <th>{t('multiday.difficulty')}</th>
                <th>{t('multiday.region')}</th>
                <th>{t('admin.status')}</th>
                <th>{t('common.actions', 'Actions')}</th>
              </tr>
            </thead>
            <tbody>
              {trails.length === 0 ? (
                <tr>
                  <td colSpan="8" style={{ textAlign: 'center', padding: '40px' }}>
                    {t('admin.noTrailsYet')}
                  </td>
                </tr>
              ) : (
                trails.map(trail => (
                  <tr key={trail.id}>
                    <td>{trail.id}</td>
                    <td>{trail.name}</td>
                    <td>{trail.duration_days}D/{trail.duration_nights}N</td>
                    <td>{trail.stages?.length || 0}</td>
                    <td>
                      <span className={`difficulty-badge ${trail.difficulty}`}>
                        {t(`difficulty.${trail.difficulty}`, trail.difficulty)}
                      </span>
                    </td>
                    <td>{trail.region}</td>
                    <td>
                      <span className={`status-badge ${trail.status}`}>
                        {t(`admin.${trail.status}`, trail.status)}
                      </span>
                    </td>
                    <td className="actions">
                      <button onClick={() => { setEditingTrail(trail); setIsCreating(false); }}>
                        ✏️ {t('admin.edit')}
                      </button>
                      <button onClick={() => handleDelete(trail.id)} className="delete-btn">
                        🗑️ {t('admin.delete')}
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      )}

      {editingTrail && (
        <div className="trail-editor">
          <div className="editor-header">
            <h3>{isCreating ? t('admin.createNewMultiDay') : `${t('admin.editing')}: ${editingTrail.name}`}</h3>
            <div className="editor-actions">
              <button onClick={handleSave} className="save-btn">
                💾 {t('admin.saveTrail')}
              </button>
              <button onClick={() => { setEditingTrail(null); setIsCreating(false); }} className="cancel-btn">
                {t('admin.cancel')}
              </button>
            </div>
          </div>

          <div className="editor-sections">
            {/* Basic Info Section */}
            <div className="editor-section">
              <h4>📋 {t('admin.basicInfo')}</h4>
              <div className="form-grid">
                <div className="form-group">
                  <label>{t('admin.trailId')} *</label>
                  <input
                    type="text"
                    value={editingTrail.id}
                    onChange={(e) => updateField('id', e.target.value)}
                    disabled={!isCreating}
                    placeholder={t('admin.trailIdPlaceholder')}
                  />
                </div>
                <div className="form-group">
                  <label>{t('admin.trailName')} *</label>
                  <input
                    type="text"
                    value={editingTrail.name}
                    onChange={(e) => updateField('name', e.target.value)}
                    placeholder={t('admin.trailNamePlaceholder')}
                  />
                </div>
                <div className="form-group">
                  <label>{t('admin.type')}</label>
                  <select value={editingTrail.type} onChange={(e) => updateField('type', e.target.value)}>
                    <option value="point-to-point">{t('admin.pointToPoint')}</option>
                    <option value="loop">{t('admin.loop')}</option>
                    <option value="out-and-back">{t('admin.outAndBack')}</option>
                  </select>
                </div>
                <div className="form-group">
                  <label>{t('admin.durationDays')}</label>
                  <input
                    type="number"
                    value={editingTrail.duration_days}
                    onChange={(e) => updateField('duration_days', parseInt(e.target.value))}
                    min="2"
                  />
                </div>
                <div className="form-group">
                  <label>{t('admin.durationNights')}</label>
                  <input
                    type="number"
                    value={editingTrail.duration_nights}
                    onChange={(e) => updateField('duration_nights', parseInt(e.target.value))}
                    min="1"
                  />
                </div>
                <div className="form-group">
                  <label>{t('multiday.difficulty')}</label>
                  <select value={editingTrail.difficulty} onChange={(e) => updateField('difficulty', e.target.value)}>
                    <option value="easy">{t('difficulty.easy')}</option>
                    <option value="moderate">{t('difficulty.moderate')}</option>
                    <option value="challenging">{t('difficulty.challenging')}</option>
                    <option value="expert">{t('difficulty.expert')}</option>
                  </select>
                </div>
                <div className="form-group">
                  <label>{t('multiday.region')}</label>
                  <input
                    type="text"
                    value={editingTrail.region}
                    onChange={(e) => updateField('region', e.target.value)}
                    placeholder={t('admin.regionPlaceholder')}
                  />
                </div>
                <div className="form-group">
                  <label>{t('admin.status')}</label>
                  <select value={editingTrail.status} onChange={(e) => updateField('status', e.target.value)}>
                    <option value="draft">{t('admin.draft')}</option>
                    <option value="published">{t('admin.published')}</option>
                  </select>
                </div>
              </div>
              <div className="form-group">
                <label>{t('admin.description')}</label>
                <textarea
                  value={editingTrail.description}
                  onChange={(e) => updateField('description', e.target.value)}
                  rows="4"
                  placeholder={t('admin.descriptionPlaceholder')}
                />
              </div>
            </div>

            {/* Media Section */}
            <div className="editor-section">
              <h4>🖼️ {t('admin.media')}</h4>
              <div className="form-grid">
                <div className="form-group">
                  <label>{t('admin.heroImageUrl')}</label>
                  <input
                    type="text"
                    value={editingTrail.hero_image}
                    onChange={(e) => updateField('hero_image', e.target.value)}
                    placeholder="https://..."
                  />
                </div>
                <div className="form-group">
                  <label>{t('admin.thumbnailUrl')}</label>
                  <input
                    type="text"
                    value={editingTrail.thumbnail}
                    onChange={(e) => updateField('thumbnail', e.target.value)}
                    placeholder="https://..."
                  />
                </div>
              </div>
            </div>

            {/* Stages Section */}
            <div className="editor-section">
              <div className="section-header">
                <h4>🥾 {t('admin.trailStages')} ({editingTrail.stages?.length || 0})</h4>
                <button onClick={handleAddStage} className="add-stage-btn">
                  + {t('admin.addStage')}
                </button>
              </div>

              {editingTrail.stages?.map((stage, index) => (
                <div key={index} className="stage-card">
                  <div className="stage-header">
                    <h5>{t('admin.stage')} {stage.stage_number}: {stage.name || t('admin.unnamed')}</h5>
                    <button onClick={() => handleRemoveStage(index)} className="remove-stage-btn">
                      🗑️ {t('admin.remove')}
                    </button>
                  </div>

                  <div className="form-grid">
                    <div className="form-group">
                      <label>{t('admin.stageName')}</label>
                      <input
                        type="text"
                        value={stage.name}
                        onChange={(e) => updateStage(index, 'name', e.target.value)}
                        placeholder={t('admin.stagePlaceholder')}
                      />
                    </div>
                    <div className="form-group">
                      <label>{t('admin.distanceKm')}</label>
                      <input
                        type="number"
                        step="0.1"
                        value={stage.distance_km}
                        onChange={(e) => updateStage(index, 'distance_km', parseFloat(e.target.value))}
                      />
                    </div>
                    <div className="form-group">
                      <label>{t('admin.elevationGainM')}</label>
                      <input
                        type="number"
                        value={stage.elevation_gain_m}
                        onChange={(e) => updateStage(index, 'elevation_gain_m', parseInt(e.target.value))}
                      />
                    </div>
                    <div className="form-group">
                      <label>{t('admin.elevationLossM')}</label>
                      <input
                        type="number"
                        value={stage.elevation_loss_m}
                        onChange={(e) => updateStage(index, 'elevation_loss_m', parseInt(e.target.value))}
                      />
                    </div>
                    <div className="form-group">
                      <label>{t('admin.durationHours')}</label>
                      <input
                        type="number"
                        step="0.5"
                        value={stage.estimated_duration_hours}
                        onChange={(e) => updateStage(index, 'estimated_duration_hours', parseFloat(e.target.value))}
                      />
                    </div>
                    <div className="form-group">
                      <label>{t('multiday.difficulty')}</label>
                      <select
                        value={stage.difficulty}
                        onChange={(e) => updateStage(index, 'difficulty', e.target.value)}
                      >
                        <option value="easy">{t('difficulty.easy')}</option>
                        <option value="moderate">{t('difficulty.moderate')}</option>
                        <option value="challenging">{t('difficulty.challenging')}</option>
                        <option value="expert">{t('difficulty.expert')}</option>
                      </select>
                    </div>
                    <div className="form-group full-width">
                      <label>{t('admin.overnightRifugioName')}</label>
                      <input
                        type="text"
                        value={stage.overnight_rifugio_name}
                        onChange={(e) => updateStage(index, 'overnight_rifugio_name', e.target.value)}
                        placeholder={t('admin.overnightRifugioPlaceholder')}
                      />
                    </div>
                  </div>

                  <div className="form-group">
                    <label>{t('admin.stageDescription')}</label>
                    <textarea
                      value={stage.description}
                      onChange={(e) => updateStage(index, 'description', e.target.value)}
                      rows="3"
                      placeholder={t('admin.stageDescriptionPlaceholder')}
                    />
                  </div>
                </div>
              ))}

              {(!editingTrail.stages || editingTrail.stages.length === 0) && (
                <div className="empty-stages">
                  {t('admin.noStagesYet')}
                </div>
              )}
            </div>

            {/* Summary Section */}
            <div className="editor-section stats-section">
              <h4>📊 {t('admin.trailSummary')}</h4>
              <div className="stats-grid">
                <div className="stat-card">
                  <div className="stat-label">{t('admin.totalDistance')}</div>
                  <div className="stat-value">
                    {editingTrail.stages?.reduce((sum, s) => sum + (parseFloat(s.distance_km) || 0), 0).toFixed(1)} km
                  </div>
                </div>
                <div className="stat-card">
                  <div className="stat-label">{t('admin.totalElevationGain')}</div>
                  <div className="stat-value">
                    {editingTrail.stages?.reduce((sum, s) => sum + (parseInt(s.elevation_gain_m) || 0), 0)} m
                  </div>
                </div>
                <div className="stat-card">
                  <div className="stat-label">{t('admin.totalElevationLoss')}</div>
                  <div className="stat-value">
                    {editingTrail.stages?.reduce((sum, s) => sum + (parseInt(s.elevation_loss_m) || 0), 0)} m
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default MultiDayTrailsManager;

web-frontend/src/components/MultiDayTrai.content:
.multiday-trails-page {
  min-height: 100vh;
  background: linear-gradient(180deg, #0a0e1a 0%, #1a1f2e 100%);
}

/* Hero Section */
.multiday-hero {
  position: relative;
  height: 50vh;
  min-height: 400px;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  background-image: url('https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=1600'),
    linear-gradient(135deg, rgba(102, 126, 234, 0.8) 0%, rgba(118, 75, 162, 0.8) 100%);
  background-size: cover;
  background-position: center;
  background-blend-mode: overlay;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
}

.multiday-hero-overlay {
  position: absolute;
  inset: 0;
  background: radial-gradient(circle at 50% 50%, transparent 0%, rgba(10, 14, 26, 0.4) 100%);
}

.multiday-hero-content {
  position: relative;
  z-index: 2;
  text-align: center;
  padding: 40px 20px;
  max-width: 800px;
}

.multiday-hero-title {
  font-size: 56px;
  font-weight: 900;
  color: white;
  margin: 0 0 20px 0;
  text-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);
  letter-spacing: -1px;
}

.multiday-hero-subtitle {
  font-size: 20px;
  color: rgba(255, 255, 255, 0.9);
  margin: 0;
  text-shadow: 0 2px 10px rgba(0, 0, 0, 0.2);
  font-weight: 400;
}

/* Container */
.multiday-container {
  display: flex;
  gap: 30px;
  max-width: 1400px;
  margin: -60px auto 0;
  padding: 0 20px 60px;
  position: relative;
  z-index: 3;
}

/* Sidebar */
.multiday-sidebar {
  width: 320px;
  flex-shrink: 0;
  background: rgba(255, 255, 255, 0.05);
  backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 16px;
  padding: 24px;
  height: fit-content;
  position: sticky;
  top: 20px;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
}

.filter-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 24px;
}

.filter-header h3 {
  font-size: 20px;
  font-weight: 700;
  color: white;
  margin: 0;
}

.clear-filters-btn {
  background: rgba(255, 255, 255, 0.1);
  color: rgba(255, 255, 255, 0.8);
  border: none;
  padding: 6px 12px;
  border-radius: 6px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s ease;
}

.clear-filters-btn:hover {
  background: rgba(255, 255, 255, 0.15);
  color: white;
}

.filter-section {
  margin-bottom: 20px;
}

.filter-section label {
  display: block;
  font-size: 13px;
  font-weight: 600;
  color: rgba(255, 255, 255, 0.7);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 8px;
}

.filter-section input,
.filter-section select {
  width: 100%;
  padding: 10px 12px;
  background: rgba(255, 255, 255, 0.08);
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 8px;
  color: white;
  font-size: 14px;
  transition: all 0.2s ease;
}

.filter-section input::placeholder {
  color: rgba(255, 255, 255, 0.4);
}

.filter-section input:focus,
.filter-section select:focus {
  outline: none;
  background: rgba(255, 255, 255, 0.12);
  border-color: #667eea;
}

.duration-inputs {
  display: flex;
  align-items: center;
  gap: 8px;
}

.duration-inputs input {
  flex: 1;
}

.duration-inputs span {
  color: rgba(255, 255, 255, 0.5);
  font-weight: 600;
}

.filter-stats {
  margin-top: 24px;
  padding-top: 20px;
  border-top: 1px solid rgba(255, 255, 255, 0.1);
  display: flex;
  justify-content: space-between;
}

.stat-item {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.stat-label {
  font-size: 11px;
  color: rgba(255, 255, 255, 0.6);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  font-weight: 600;
}

.stat-value {
  font-size: 24px;
  font-weight: 700;
  color: #667eea;
}

/* Content Area */
.multiday-content {
  flex: 1;
  min-width: 0;
}

.multiday-header-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 30px;
  padding: 20px;
  background: rgba(255, 255, 255, 0.05);
  backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 12px;
}

.multiday-header-bar h2 {
  font-size: 24px;
  font-weight: 700;
  color: white;
  margin: 0;
}

.results-count {
  font-size: 14px;
  color: rgba(255, 255, 255, 0.6);
  font-weight: 600;
}

/* Trails Grid */
.trails-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(350px, 1fr));
  gap: 24px;
}

.trail-card {
  background: rgba(255, 255, 255, 0.05);
  backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 16px;
  overflow: hidden;
  cursor: pointer;
  transition: all 0.3s ease;
}

.trail-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 40px rgba(102, 126, 234, 0.3);
  border-color: rgba(102, 126, 234, 0.5);
}

.trail-card-image {
  position: relative;
  height: 220px;
  overflow: hidden;
}

.trail-card-image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.3s ease;
}

.trail-card:hover .trail-card-image img {
  transform: scale(1.05);
}

.trail-card-type-badge {
  position: absolute;
  top: 12px;
  right: 12px;
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: blur(10px);
  color: white;
  padding: 6px 12px;
  border-radius: 20px;
  font-size: 12px;
  font-weight: 600;
  text-transform: capitalize;
}

.trail-card-content {
  padding: 20px;
}

.trail-card-title {
  font-size: 20px;
  font-weight: 700;
  color: white;
  margin: 0 0 16px 0;
  line-height: 1.3;
}

.trail-card-stats {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 12px;
  margin-bottom: 16px;
}

.trail-card-stats .stat {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 14px;
  color: rgba(255, 255, 255, 0.8);
}

.trail-card-stats .stat-icon {
  font-size: 16px;
}

.trail-card-description {
  font-size: 14px;
  color: rgba(255, 255, 255, 0.7);
  line-height: 1.6;
  margin: 0 0 16px 0;
}

.trail-card-footer {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16px;
  padding-top: 16px;
  border-top: 1px solid rgba(255, 255, 255, 0.1);
}

.trail-card-region {
  font-size: 13px;
  color: rgba(255, 255, 255, 0.7);
  font-weight: 600;
}

.trail-card-difficulty {
  padding: 4px 12px;
  border-radius: 20px;
  font-size: 12px;
  font-weight: 600;
  text-transform: capitalize;
}

.trail-card-btn {
  width: 100%;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  border: none;
  padding: 12px 20px;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
}

.trail-card-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 20px rgba(102, 126, 234, 0.4);
}

/* No Trails State */
.no-trails {
  text-align: center;
  padding: 80px 20px;
  background: rgba(255, 255, 255, 0.05);
  backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 16px;
}

.no-trails-icon {
  font-size: 80px;
  margin-bottom: 20px;
  opacity: 0.5;
}

.no-trails h3 {
  font-size: 24px;
  font-weight: 700;
  color: white;
  margin: 0 0 12px 0;
}

.no-trails p {
  font-size: 16px;
  color: rgba(255, 255, 255, 0.6);
  margin: 0 0 24px 0;
}

.reset-btn {
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  border: none;
  padding: 12px 24px;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
}

.reset-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 20px rgba(102, 126, 234, 0.4);
}

/* Loading State */
.multiday-loading {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  background: linear-gradient(180deg, #0a0e1a 0%, #1a1f2e 100%);
}

.loading-spinner {
  width: 50px;
  height: 50px;
  border: 4px solid rgba(255, 255, 255, 0.1);
  border-top-color: #667eea;
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

.multiday-loading p {
  color: rgba(255, 255, 255, 0.6);
  margin-top: 20px;
  font-size: 16px;
}

/* Responsive */
@media (max-width: 1024px) {
  .multiday-container {
    flex-direction: column;
  }

  .multiday-sidebar {
    width: 100%;
    position: static;
  }

  .trails-grid {
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  }
}

@media (max-width: 768px) {
  .multiday-hero-title {
    font-size: 36px;
  }

  .multiday-hero-subtitle {
    font-size: 16px;
  }

  .trails-grid {
    grid-template-columns: 1fr;
  }

  .multiday-header-bar {
    flex-direction: column;
    align-items: flex-start;
    gap: 12px;
  }
}

.multiday-detail-page {
  min-height: 100vh;
  background: linear-gradient(180deg, #0a0e1a 0%, #1a1f2e 100%);
}

/* Hero Section */
.multiday-detail-hero {
  position: relative;
  height: 60vh;
  min-height: 500px;
  background-size: cover;
  background-position: center;
