  inset: 0;
  background: linear-gradient(to bottom, rgba(10, 14, 26, 0.4) 0%, rgba(10, 14, 26, 0.9) 100%);
}

.multiday-detail-hero-content {
  position: relative;
  z-index: 2;
  padding: 60px 40px;
  max-width: 1400px;
  margin: 0 auto;
  width: 100%;
}

.back-btn {
  background: rgba(255, 255, 255, 0.15);
  backdrop-filter: blur(10px);
  color: white;
  border: 1px solid rgba(255, 255, 255, 0.2);
  padding: 10px 20px;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  margin-bottom: 24px;
}

.back-btn:hover {
  background: rgba(255, 255, 255, 0.25);
}

.multiday-detail-title {
  font-size: 48px;
  font-weight: 900;
  color: white;
  margin: 0 0 20px 0;
  text-shadow: 0 4px 20px rgba(0, 0, 0, 0.5);
  letter-spacing: -1px;
}

.multiday-detail-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 16px;
}

.meta-item {
  background: rgba(255, 255, 255, 0.15);
  backdrop-filter: blur(10px);
  padding: 8px 16px;
  border-radius: 20px;
  font-size: 14px;
  font-weight: 600;
  color: white;
}

.meta-item.difficulty-badge {
  padding: 8px 16px;
  text-transform: capitalize;
}

/* Container */
.multiday-detail-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 40px 20px 80px;
}

.detail-section {
  background: rgba(255, 255, 255, 0.05);
  backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 16px;
  padding: 32px;
  margin-bottom: 32px;
}

.detail-section h2 {
  font-size: 28px;
  font-weight: 700;
  color: white;
  margin: 0 0 24px 0;
}

.detail-section h4 {
  font-size: 18px;
  font-weight: 700;
  color: white;
  margin: 0 0 16px 0;
}

/* Overview Section */
.overview-description {
  font-size: 16px;
  line-height: 1.8;
  color: rgba(255, 255, 255, 0.8);
  margin: 0 0 32px 0;
}

.highlights-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 16px;
}

.highlight-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 16px;
  background: rgba(102, 126, 234, 0.1);
  border: 1px solid rgba(102, 126, 234, 0.2);
  border-radius: 10px;
  color: white;
  font-size: 14px;
  font-weight: 500;
}

.highlight-icon {
  font-size: 20px;
}

/* Stages Section */
.stages-nav {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 12px;
  margin-bottom: 32px;
}

.stage-nav-btn {
  background: rgba(255, 255, 255, 0.05);
  border: 2px solid rgba(255, 255, 255, 0.1);
  border-radius: 12px;
  padding: 16px;
  cursor: pointer;
  transition: all 0.3s ease;
  text-align: left;
}

.stage-nav-btn:hover {
  background: rgba(255, 255, 255, 0.08);
  border-color: rgba(102, 126, 234, 0.5);
}

.stage-nav-btn.active {
  background: linear-gradient(135deg, rgba(102, 126, 234, 0.2) 0%, rgba(118, 75, 162, 0.2) 100%);
  border-color: #667eea;
}

.stage-nav-number {
  font-size: 12px;
  color: rgba(255, 255, 255, 0.6);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 4px;
}

.stage-nav-name {
  font-size: 14px;
  color: white;
  font-weight: 600;
  margin-bottom: 8px;
  line-height: 1.3;
}

.stage-nav-stats {
  font-size: 12px;
  color: rgba(255, 255, 255, 0.5);
}

/* Stage Detail Card */
.stage-detail-card {
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 12px;
  padding: 28px;
}

.stage-detail-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 20px;
  margin-bottom: 28px;
}

.stage-detail-header h3 {
  font-size: 24px;
  font-weight: 700;
  color: white;
  margin: 0 0 12px 0;
}

.stage-description {
  font-size: 15px;
  line-height: 1.7;
  color: rgba(255, 255, 255, 0.7);
  margin: 0;
}

.stage-difficulty-badge {
  flex-shrink: 0;
  padding: 8px 16px;
  border-radius: 20px;
  font-size: 13px;
  font-weight: 600;
  text-transform: capitalize;
}

/* Stage Stats Grid */
.stage-stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 16px;
  margin-bottom: 28px;
}

.stage-stat {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 16px;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 10px;
}

.stage-stat-icon {
  font-size: 28px;
}

.stage-stat-content {
  flex: 1;
}

.stage-stat-label {
  font-size: 12px;
  color: rgba(255, 255, 255, 0.6);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 4px;
}

.stage-stat-value {
  font-size: 20px;
  font-weight: 700;
  color: white;
}

/* Route Points */
.route-points {
  display: flex;
  align-items: center;
  gap: 20px;
  margin-bottom: 28px;
  padding: 24px;
  background: rgba(102, 126, 234, 0.08);
  border-radius: 12px;
}

.route-point {
  display: flex;
  align-items: center;
  gap: 12px;
  flex: 1;
}

.route-point-icon {
  width: 50px;
  height: 50px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 24px;
  flex-shrink: 0;
}

.route-point-icon.start {
  background: linear-gradient(135deg, #4caf50 0%, #66bb6a 100%);
}

.route-point-icon.end {
  background: linear-gradient(135deg, #f44336 0%, #ef5350 100%);
}

.route-point-content {
  flex: 1;
}

.route-point-label {
  font-size: 11px;
  color: rgba(255, 255, 255, 0.6);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 4px;
}

.route-point-name {
  font-size: 16px;
  color: white;
  font-weight: 700;
  margin-bottom: 4px;
}

.route-point-elevation {
  font-size: 13px;
  color: rgba(255, 255, 255, 0.7);
}

.route-connector {
  height: 2px;
  flex: 1;
  background: linear-gradient(to right, #4caf50, #f44336);
  border-radius: 2px;
  position: relative;
}

.route-connector::after {
  content: '→';
  position: absolute;
  right: -10px;
  top: 50%;
  transform: translateY(-50%);
  color: #f44336;
  font-size: 20px;
}

/* Overnight Rifugio */
.overnight-rifugio {
  margin-bottom: 28px;
}

.rifugio-card {
  background: rgba(102, 126, 234, 0.1);
  border: 1px solid rgba(102, 126, 234, 0.3);
  border-radius: 12px;
  padding: 20px;
}

.rifugio-info {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.rifugio-name {
  font-size: 18px;
  font-weight: 700;
  color: white;
}

.rifugio-details {
  display: flex;
  flex-wrap: wrap;
  gap: 16px;
  font-size: 14px;
  color: rgba(255, 255, 255, 0.8);
}

/* Stage Highlights */
.stage-highlights ul {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  gap: 8px;
}

.stage-highlights li {
  padding: 12px 16px;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 8px;
  color: rgba(255, 255, 255, 0.8);
  font-size: 14px;
  line-height: 1.6;
}

.stage-highlights li::before {
  content: '✓';
  display: inline-block;
  margin-right: 12px;
  color: #4caf50;
  font-weight: 700;
}

/* Planning Section */
.planning-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 24px;
}

.equipment-toggle-btn {
  background: rgba(102, 126, 234, 0.2);
  color: white;
  border: 1px solid rgba(102, 126, 234, 0.4);
  padding: 10px 16px;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
}

.equipment-toggle-btn:hover {
  background: rgba(102, 126, 234, 0.3);
}

.equipment-checklist {
  margin-bottom: 28px;
}

.checklist-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
  gap: 12px;
}

.checklist-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px 16px;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 8px;
  color: white;
  font-size: 14px;
  transition: all 0.2s ease;
}

.checklist-item:hover {
  background: rgba(255, 255, 255, 0.08);
}

.checklist-checkbox {
  font-size: 18px;
  color: rgba(255, 255, 255, 0.5);
}

/* Booking Tips */
.booking-tips {
  margin-bottom: 28px;
}

.booking-tips ul {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  gap: 12px;
}

.booking-tips li {
  padding: 16px;
  background: rgba(255, 193, 7, 0.1);
  border: 1px solid rgba(255, 193, 7, 0.3);
  border-radius: 10px;
  color: rgba(255, 255, 255, 0.9);
  font-size: 14px;
  line-height: 1.6;
}

.booking-tips li::before {
  content: '💡';
  display: inline-block;
  margin-right: 12px;
}

/* Season Info */
.season-info {
  padding: 20px;
  background: rgba(102, 126, 234, 0.1);
  border: 1px solid rgba(102, 126, 234, 0.3);
  border-radius: 10px;
}

.season-info p {
  margin: 0;
  font-size: 16px;
  color: white;
  font-weight: 600;
}

/* Gallery Section */
.photos-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 16px;
}

.photo-item {
  position: relative;
  padding-bottom: 66.67%;
  overflow: hidden;
  border-radius: 12px;
}

.photo-item img {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.3s ease;
}

.photo-item:hover img {
  transform: scale(1.05);
}

/* CTA Section */
.cta-section {
  text-align: center;
  background: linear-gradient(135deg, rgba(102, 126, 234, 0.15) 0%, rgba(118, 75, 162, 0.15) 100%);
  border: 2px solid rgba(102, 126, 234, 0.3);
}

.cta-section h3 {
  font-size: 28px;
  font-weight: 700;
  color: white;
  margin: 0 0 12px 0;
}

.cta-section p {
  font-size: 16px;
  color: rgba(255, 255, 255, 0.7);
  margin: 0 0 28px 0;
}

.cta-buttons {
  display: flex;
  gap: 16px;
  justify-content: center;
  flex-wrap: wrap;
}

.cta-btn {
  padding: 14px 28px;
  border: none;
  border-radius: 10px;
  font-size: 16px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
}

.cta-btn.primary {
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  box-shadow: 0 6px 20px rgba(102, 126, 234, 0.4);
}

.cta-btn.primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(102, 126, 234, 0.5);
}

.cta-btn.secondary {
  background: rgba(255, 255, 255, 0.1);
  color: white;
  border: 2px solid rgba(255, 255, 255, 0.2);
}

.cta-btn.secondary:hover {
  background: rgba(255, 255, 255, 0.15);
}

/* Loading & Error States */
.multiday-detail-loading,
.multiday-detail-error {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  background: linear-gradient(180deg, #0a0e1a 0%, #1a1f2e 100%);
}

.multiday-detail-loading p,
.multiday-detail-error h2 {
  color: white;
  margin-top: 20px;
}

.multiday-detail-error button {
  margin-top: 20px;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  border: none;
  padding: 12px 24px;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
}

/* Responsive */
@media (max-width: 1024px) {
  .multiday-detail-title {
    font-size: 36px;
  }

  .route-points {
    flex-direction: column;
    align-items: stretch;
  }

  .route-connector {
    width: 2px;
    height: 40px;
    background: linear-gradient(to bottom, #4caf50, #f44336);
  }

  .route-connector::after {
    content: '↓';
    right: auto;
    left: 50%;
    top: auto;
    bottom: -15px;
    transform: translateX(-50%);
  }
}

@media (max-width: 768px) {
  .multiday-detail-hero-content {
    padding: 40px 20px;
  }

  .multiday-detail-title {
    font-size: 28px;
  }

  .multiday-detail-meta {
    gap: 8px;
  }

  .meta-item {
    font-size: 12px;
    padding: 6px 12px;
  }

  .detail-section {
    padding: 20px;
  }

  .detail-section h2 {
    font-size: 22px;
  }

  .stages-nav {
    grid-template-columns: 1fr;
  }

  .stage-detail-header {
    flex-direction: column;
  }

  .stage-stats-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .highlights-grid {
    grid-template-columns: 1fr;
  }

  .checklist-grid {
    grid-template-columns: 1fr;
  }

  .photos-grid {
    grid-template-columns: 1fr;
  }

  .cta-buttons {
    flex-direction: column;
  }

  .cta-btn {
    width: 100%;
  }
}

