.rifugio-detail-page {
  min-height: 100vh;
  background: linear-gradient(180deg, #0a0a0a 0%, #1a1a2e 50%, #0a0a0a 100%);
  padding-bottom: 60px;
}

/* Hero Section */
.rifugio-hero {
  position: relative;
  height: 500px;
  overflow: hidden;
}

.hero-image {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.hero-overlay {
  position: absolute;
  inset: 0;
  background: linear-gradient(180deg, rgba(0,0,0,0.3) 0%, rgba(0,0,0,0.7) 100%);
}

.back-button-hero {
  position: absolute;
  top: 24px;
  left: 24px;
  background: rgba(0, 0, 0, 0.6);
  backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.2);
  color: white;
  padding: 12px 24px;
  border-radius: 8px;
  cursor: pointer;
  font-size: 16px;
  font-weight: 600;
  transition: all 0.3s ease;
  z-index: 10;
}

.back-button-hero:hover {
  background: rgba(212, 165, 116, 0.3);
  border-color: rgba(212, 165, 116, 0.5);
  transform: translateX(-4px);
}

.hero-content {
  position: absolute;
  bottom: 40px;
  left: 40px;
  right: 40px;
  z-index: 10;
}

.rifugio-title {
  font-size: 48px;
  font-weight: 800;
  color: white;
  margin: 0 0 16px 0;
  text-shadow: 0 4px 20px rgba(0, 0, 0, 0.8);
}

.status-badge-large {
  display: inline-block;
  padding: 12px 24px;
  border-radius: 24px;
  font-size: 16px;
  font-weight: 600;
  backdrop-filter: blur(10px);
}

/* Quick Stats Bar */
.quick-stats-bar {
  display: flex;
  gap: 24px;
  max-width: 1400px;
  margin: -60px auto 40px;
  padding: 0 24px;
  position: relative;
  z-index: 20;
  overflow-x: auto;
}

.stat-item {
  flex: 1;
  min-width: 200px;
  background: linear-gradient(135deg, rgba(212, 165, 116, 0.15) 0%, rgba(255, 255, 255, 0.03) 100%);
  backdrop-filter: blur(20px);
  border: 1px solid rgba(212, 165, 116, 0.25);
  border-radius: 16px;
  padding: 24px;
  display: flex;
  align-items: center;
  gap: 16px;
}

.stat-icon {
  font-size: 32px;
}

.stat-value {
  font-size: 24px;
  font-weight: 700;
  color: white;
  margin-bottom: 4px;
}

.stat-label {
  font-size: 13px;
  color: rgba(255, 255, 255, 0.6);
  text-transform: uppercase;
  letter-spacing: 1px;
}

/* Content Container */
.rifugio-content-container {
  max-width: 1400px;
  margin: 0 auto;
  padding: 0 24px;
  display: grid;
  grid-template-columns: 1fr 380px;
  gap: 40px;
}

.rifugio-main-content {
  min-width: 0;
}

.rifugio-sidebar {
  position: sticky;
  top: 24px;
  height: fit-content;
}

/* Content Sections */
.content-section {
  margin-bottom: 48px;
}

.section-title {
  font-size: 28px;
  font-weight: 700;
  color: #D4A574;
  margin: 0 0 24px 0;
}

.rifugio-description {
  color: rgba(255, 255, 255, 0.85);
  font-size: 16px;
  line-height: 1.8;
}

/* Facilities Grid */
.facilities-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 16px;
}

.facility-item {
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 12px;
  padding: 16px;
  display: flex;
  align-items: center;
  gap: 12px;
  color: white;
  font-size: 15px;
}

.facility-icon {
  font-size: 24px;
}

/* Photo Gallery */
.photo-gallery-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
  gap: 16px;
}

.gallery-photo {
  width: 100%;
  height: 200px;
  object-fit: cover;
  border-radius: 12px;
  cursor: pointer;
  transition: transform 0.3s ease;
}

.gallery-photo:hover {
  transform: scale(1.05);
}

/* Sidebar Cards */
.sidebar-card {
  background: rgba(255, 255, 255, 0.03);
  backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 16px;
  padding: 24px;
  margin-bottom: 20px;
}

.sidebar-title {
  font-size: 18px;
  font-weight: 700;
  color: #D4A574;
  margin: 0 0 16px 0;
}

.season-dates {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.season-date-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.date-label {
  color: rgba(255, 255, 255, 0.6);
  font-size: 14px;
}

.date-value {
  color: white;
  font-weight: 600;
}

.pricing-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.price-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding-bottom: 12px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.price-item:last-child {
  border-bottom: none;
  padding-bottom: 0;
}

.price {
  color: #D4A574;
  font-size: 18px;
  font-weight: 700;
}

.contact-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.contact-item {
  display: block;
  color: rgba(255, 255, 255, 0.85);
  text-decoration: none;
  padding: 12px;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 8px;
  transition: all 0.3s ease;
}

.contact-item:hover {
  background: rgba(212, 165, 116, 0.15);
  color: #D4A574;
}

.booking-cta-btn {
  width: 100%;
  padding: 18px;
  background: linear-gradient(135deg, #D4A574 0%, #B8935E 100%);
  border: none;
  border-radius: 12px;
  color: white;
  font-size: 16px;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.3s ease;
}

.booking-cta-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(212, 165, 116, 0.4);
}

/* Booking Modal */
.booking-modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.8);
  backdrop-filter: blur(4px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  padding: 20px;
}

.booking-modal {
  background: linear-gradient(135deg, #1a1a2e 0%, #0f0f1e 100%);
  border: 1px solid rgba(212, 165, 116, 0.3);
  border-radius: 20px;
  max-width: 600px;
  width: 100%;
  max-height: 90vh;
  overflow-y: auto;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.5);
}

.booking-modal-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 24px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.booking-modal-header h2 {
  color: #D4A574;
  font-size: 24px;
  margin: 0;
}

.modal-close-btn {
  background: none;
  border: none;
  color: rgba(255, 255, 255, 0.6);
  font-size: 32px;
  cursor: pointer;
  transition: color 0.3s ease;
}

.modal-close-btn:hover {
  color: white;
}

.booking-form {
  padding: 24px;
}

.form-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
  margin-bottom: 16px;
}

.form-group {
  margin-bottom: 16px;
}

.form-group label {
  display: block;
  color: rgba(255, 255, 255, 0.8);
  font-size: 14px;
  font-weight: 600;
  margin-bottom: 8px;
}

.form-group input,
.form-group select,
.form-group textarea {
  width: 100%;
  padding: 12px;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 8px;
  color: white;
  font-size: 14px;
}

.form-group input:focus,
.form-group select:focus,
.form-group textarea:focus {
  outline: none;
  border-color: rgba(212, 165, 116, 0.5);
  background: rgba(255, 255, 255, 0.08);
}

.form-checkbox {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 24px;
}

.form-checkbox input[type="checkbox"] {
  width: 20px;
  height: 20px;
  cursor: pointer;
}

.form-checkbox label {
  color: rgba(255, 255, 255, 0.85);
  cursor: pointer;
}

.booking-submit-btn {
  width: 100%;
  padding: 16px;
  background: linear-gradient(135deg, #D4A574 0%, #B8935E 100%);
  border: none;
  border-radius: 12px;
  color: white;
  font-size: 16px;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.3s ease;
}

.booking-submit-btn:hover:not(:disabled) {
  transform: translateY(-2px);
  box-shadow: 0 8px 24px rgba(212, 165, 116, 0.4);
}

.booking-submit-btn:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

.booking-success-alert {
  background: rgba(34, 197, 94, 0.2);
  border: 1px solid rgba(34, 197, 94, 0.4);
  color: #22c55e;
  padding: 16px;
  border-radius: 12px;
  margin-bottom: 24px;
  font-weight: 600;
}

/* Mobile Responsive */
@media (max-width: 1024px) {
  .rifugio-content-container {
    grid-template-columns: 1fr;
  }

  .rifugio-sidebar {
    position: static;
  }

  .quick-stats-bar {
    flex-wrap: wrap;
    margin-top: 24px;
  }
}

@media (max-width: 768px) {
  .rifugio-title {
    font-size: 32px;
  }

  .hero-content {
    bottom: 24px;
    left: 20px;
    right: 20px;
  }

  .form-row {
    grid-template-columns: 1fr;
  }

  .facilities-grid {
    grid-template-columns: 1fr;
  }

  .photo-gallery-grid {
    grid-template-columns: 1fr;
  }
}

web-frontend/src/components/Rifugios.css.content:
.rifugios-page {
  min-height: 100vh;
  background: linear-gradient(180deg, #0a0a0a 0%, #1a1a2e 50%, #0a0a0a 100%);
  padding-bottom: 60px;
}

.rifugios-header {
  text-align: center;
  padding: 40px 20px;
  background: linear-gradient(135deg, rgba(212, 165, 116, 0.1) 0%, rgba(255, 255, 255, 0.02) 100%);
  border-bottom: 1px solid rgba(212, 165, 116, 0.2);
}

.page-title {
  font-size: 36px;
  font-weight: 800;
  color: #D4A574;
  margin-bottom: 12px;
}

.page-subtitle {
  color: rgba(255, 255, 255, 0.7);
  font-size: 16px;
}

.rifugios-container {
  display: flex;
  max-width: 1400px;
  margin: 0 auto;
  gap: 24px;
  padding: 24px;
}

/* Filters Sidebar */
.filters-sidebar {
  width: 280px;
  flex-shrink: 0;
  background: rgba(255, 255, 255, 0.03);
  backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 16px;
  padding: 24px;
  height: fit-content;
  position: sticky;
  top: 24px;
}

.filters-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 24px;
}

.filters-header h2 {
  font-size: 20px;
  color: #D4A574;
  margin: 0;
}

.clear-filters-btn {
  background: rgba(212, 165, 116, 0.15);
  border: 1px solid rgba(212, 165, 116, 0.3);
  color: #D4A574;
  padding: 8px 16px;
  border-radius: 8px;
  font-size: 13px;
  cursor: pointer;
  transition: all 0.3s ease;
}

.clear-filters-btn:hover {
  background: rgba(212, 165, 116, 0.25);
  transform: translateY(-1px);
}

.filter-group {
  margin-bottom: 20px;
}

.filter-group label {
  display: block;
  color: rgba(255, 255, 255, 0.8);
  font-size: 14px;
  margin-bottom: 8px;
  font-weight: 600;
}

.search-input,
.filter-select,
.altitude-input {
  width: 100%;
  padding: 12px;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 8px;
  color: white;
  font-size: 14px;
}

.search-input:focus,
.filter-select:focus,
.altitude-input:focus {
  outline: none;
  border-color: rgba(212, 165, 116, 0.5);
  background: rgba(255, 255, 255, 0.08);
}

.altitude-inputs {
  display: flex;
  gap: 8px;
}

.altitude-input {
  flex: 1;
}

.results-count {
  margin-top: 24px;
  padding: 16px;
  background: rgba(212, 165, 116, 0.1);
  border-radius: 8px;
  text-align: center;
  color: #D4A574;
  font-weight: 600;
}

/* Main Content */
.rifugios-content {
  flex: 1;
