  margin-bottom: 12px;
}

.meta-item {
  color: rgba(255, 255, 255, 0.7);
  font-size: 14px;
}

.rifugio-type-badge {
  display: inline-block;
  padding: 4px 12px;
  background: rgba(212, 165, 116, 0.2);
  border: 1px solid rgba(212, 165, 116, 0.3);
